const document: HandbookDocumentContent = {
  navHtml: "<div class=\"nav-brand\">PRACTICE · CHEAT SHEETS</div>\n  <div class=\"nav-title\">치트시트 · 빠른 점검표</div>\n  <a href=\"#bundle-index\"><span class=\"code\">INDEX</span>통합 문서</a>\n  <a href=\"#cheat-routes\"><span class=\"code\">ROUTES</span>상황별 사용 루트</a>\n  <a href=\"#doc-cheatfe\"><span class=\"code\">DOC</span>Frontend</a>\n  <a href=\"#doc-cheatbe\"><span class=\"code\">DOC</span>Backend</a>\n  <a href=\"#doc-cheatdb\"><span class=\"code\">DOC</span>Database</a>\n  <a href=\"#doc-cheatnet\"><span class=\"code\">DOC</span>Network</a>\n  <a href=\"#doc-cheatdevops\"><span class=\"code\">DOC</span>DevOps</a>\n  <a href=\"#doc-cheatlinux\"><span class=\"code\">DOC</span>Linux</a>\n  <a href=\"#doc-cheatdocker\"><span class=\"code\">DOC</span>Docker</a>\n  <a href=\"#doc-cheatinterview\"><span class=\"code\">DOC</span>Interview</a>\n  <a href=\"#doc-cheattools\"><span class=\"code\">DOC</span>Tools·Shortcuts·Commands</a>\n  <a href=\"#doc-cheatfe\"><span class=\"code\">SRC</span>Frontend</a>\n<a href=\"#cheatfe-ch1\"><span class=\"code\">FE-CS-01</span>핵심 명령·스니펫</a>\n  <a href=\"#cheatfe-ch2\"><span class=\"code\">FE-CS-02</span>판단 한 줄</a>\n  <a href=\"#cheatfe-ch3\"><span class=\"code\">FE-CS-03</span>자주 터지는 것 · 즉시 확인</a>\n  <a href=\"#cheatfe-ch4\"><span class=\"code\">FE-CS-04</span>장애 증거 1카드</a>\n  <a href=\"#doc-cheatbe\"><span class=\"code\">SRC</span>Backend</a>\n<a href=\"#cheatbe-ch1\"><span class=\"code\">BE-CS-01</span>핵심 명령·스니펫</a>\n  <a href=\"#cheatbe-ch2\"><span class=\"code\">BE-CS-02</span>판단 한 줄</a>\n  <a href=\"#cheatbe-ch3\"><span class=\"code\">BE-CS-03</span>자주 터지는 것 · 즉시 확인</a>\n  <a href=\"#cheatbe-ch4\"><span class=\"code\">BE-CS-04</span>장애 증거 1카드</a>\n  <a href=\"#doc-cheatdb\"><span class=\"code\">SRC</span>Database</a>\n<a href=\"#cheatdb-ch1\"><span class=\"code\">DB-CS-01</span>핵심 명령·스니펫</a>\n  <a href=\"#cheatdb-ch2\"><span class=\"code\">DB-CS-02</span>판단 한 줄</a>\n  <a href=\"#cheatdb-ch3\"><span class=\"code\">DB-CS-03</span>자주 터지는 것 · 즉시 확인</a>\n  <a href=\"#cheatdb-ch4\"><span class=\"code\">DB-CS-04</span>장애 증거 1카드</a>\n  <a href=\"#doc-cheatnet\"><span class=\"code\">SRC</span>Network</a>\n<a href=\"#cheatnet-ch1\"><span class=\"code\">NW-CS-01</span>핵심 명령·스니펫</a>\n  <a href=\"#cheatnet-ch2\"><span class=\"code\">NW-CS-02</span>판단 한 줄</a>\n  <a href=\"#cheatnet-ch3\"><span class=\"code\">NW-CS-03</span>자주 터지는 것 · 즉시 확인</a>\n  <a href=\"#cheatnet-ch4\"><span class=\"code\">NW-CS-04</span>장애 증거 1카드</a>\n  <a href=\"#doc-cheatdevops\"><span class=\"code\">SRC</span>DevOps</a>\n<a href=\"#cheatdevops-ch1\"><span class=\"code\">DO-CS-01</span>핵심 명령·스니펫</a>\n  <a href=\"#cheatdevops-ch2\"><span class=\"code\">DO-CS-02</span>판단 한 줄</a>\n  <a href=\"#cheatdevops-ch3\"><span class=\"code\">DO-CS-03</span>자주 터지는 것 · 즉시 확인</a>\n  <a href=\"#cheatdevops-ch4\"><span class=\"code\">DO-CS-04</span>장애 증거 1카드</a>\n  <a href=\"#doc-cheatlinux\"><span class=\"code\">SRC</span>Linux</a>\n<a href=\"#cheatlinux-ch1\"><span class=\"code\">LX-CS-01</span>핵심 명령·스니펫</a>\n  <a href=\"#cheatlinux-ch2\"><span class=\"code\">LX-CS-02</span>판단 한 줄</a>\n  <a href=\"#cheatlinux-ch3\"><span class=\"code\">LX-CS-03</span>자주 터지는 것 · 즉시 확인</a>\n  <a href=\"#cheatlinux-ch4\"><span class=\"code\">LX-CS-04</span>장애 증거 1카드</a>\n  <a href=\"#doc-cheatdocker\"><span class=\"code\">SRC</span>Docker</a>\n<a href=\"#cheatdocker-ch1\"><span class=\"code\">DK-CS-01</span>핵심 명령·스니펫</a>\n  <a href=\"#cheatdocker-ch2\"><span class=\"code\">DK-CS-02</span>판단 한 줄</a>\n  <a href=\"#cheatdocker-ch3\"><span class=\"code\">DK-CS-03</span>자주 터지는 것 · 즉시 확인</a>\n  <a href=\"#cheatdocker-ch4\"><span class=\"code\">DK-CS-04</span>장애 증거 1카드</a>\n  <a href=\"#doc-cheatinterview\"><span class=\"code\">SRC</span>Interview</a>\n<a href=\"#cheatinterview-ch1\"><span class=\"code\">IV-CS-01</span>즉답 구조 템플릿</a>\n  <a href=\"#cheatinterview-ch2\"><span class=\"code\">IV-CS-02</span>질문 유형별 접근</a>\n  <a href=\"#cheatinterview-ch3\"><span class=\"code\">IV-CS-03</span>감점 신호 · 즉시 확인</a>\n  <a href=\"#cheatinterview-ch4\"><span class=\"code\">IV-CS-04</span>모르는 질문 1카드</a>\n  <a href=\"#doc-cheattools\"><span class=\"code\">SRC</span>Tools·Shortcuts·Commands</a>\n<a href=\"#cheattools-ch1\"><span class=\"code\">TL-CS-01</span>핵심 명령·스니펫</a>\n  <a href=\"#cheattools-ch2\"><span class=\"code\">TL-CS-02</span>판단 한 줄</a>\n  <a href=\"#cheattools-ch3\"><span class=\"code\">TL-CS-03</span>자주 터지는 것 · 즉시 확인</a>\n  <a href=\"#cheattools-ch4\"><span class=\"code\">TL-CS-04</span>장애 증거 1카드</a>",
  mainHtml: "<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : PRACTICE-CHEAT-SHEETS</span>\n    <span>SCOPE : COMMANDS · SNIPPETS · TRIAGE</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>실무 치트시트 모음</h1>\n  <p class=\"hero-sub\">Frontend, Backend, Database, Network, DevOps, Linux, Docker, Interview, Tools·Shortcuts·Commands 치트시트를 통합했습니다.</p>\n  <div class=\"hero-meta\">CURATED HANDBOOK PATH · SOURCES : 9 DOCUMENTS · UPDATED 2026-06</div>\n</header>\n\n<section id=\"bundle-index\">\n<div class=\"ch-head\"><span class=\"ch-code\">INDEX</span><h2>통합 문서</h2></div>\n<p class=\"lede\">암기용 요약이 아니라 작업 중 5초 안에 찾아 복사할 참조입니다. 도메인마다 핵심 명령·스니펫, 판단 한 줄, 자주 터지는 것, 장애 증거 카드 네 블록으로 정리했습니다. 개념 설명은 개발 핸드북, 면접 답변은 커리어 핸드북이 담당합니다.</p>\n<ul><li>Frontend</li><li>Backend</li><li>Database</li><li>Network</li><li>DevOps</li><li>Linux</li><li>Docker</li><li>Interview</li><li>Tools·Shortcuts·Commands</li></ul>\n</section>\n\n<section id=\"cheat-routes\">\n<div class=\"ch-head\"><span class=\"ch-code\">ROUTES</span><h2>상황별 사용 루트</h2></div>\n<p class=\"lede\">전체를 처음부터 읽지 않습니다. 지금 겪는 상황에 맞는 문서 2~3개만 연결해 빠르게 증거를 모읍니다.</p>\n<table>\n<tr><th>상황</th><th>먼저 볼 치트시트</th><th>10분 안에 남길 증거</th><th>멈출 기준</th></tr>\n<tr><td>화면이 느림</td><td>Frontend → Tools → DevOps</td><td>Network waterfall, Performance trace, release SHA, before/after 수치</td><td>병목 계층을 못 나누면 코드 변경 중단</td></tr>\n<tr><td>API 오류 증가</td><td>Backend → Database → Tools</td><td>route, status, errorCode, requestId, slow query 또는 upstream timeout</td><td>재시도 가능 여부와 사용자 영향이 불명확하면 배포 중단</td></tr>\n<tr><td>DB 변경 리뷰</td><td>Database → Backend → DevOps</td><td>DDL lock 위험, EXPLAIN, backfill plan, rollback/verification SQL</td><td>큰 테이블 변경에 단계화 계획이 없으면 merge 중단</td></tr>\n<tr><td>연결 장애</td><td>Network → Linux → Tools</td><td>dig, nc, curl -v, server listen, firewall/route diff</td><td>출발지·목적지·포트가 특정되지 않으면 정상 판단 금지</td></tr>\n<tr><td>배포 후 장애</td><td>DevOps → Docker → Backend 또는 Frontend</td><td>image digest, config version, health check, error rate, rollback 후보</td><td>데이터 변경 동반 여부를 모르면 rollback 실행 보류</td></tr>\n<tr><td>로컬만 깨짐</td><td>Tools → Linux → Docker</td><td>runtime version, env diff, port/process, clean install, container logs</td><td>팀/CI 재현 여부를 확인하기 전 원인 단정 금지</td></tr>\n</table>\n</section>\n\n<section id=\"doc-cheatfe\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>Frontend</h2></div>\n</section>\n\n<section id=\"cheatfe-ch1\">\n    <div class=\"ch-head\"><span class=\"ch-code\">FE-CS-01</span><h2>핵심 명령·스니펫</h2></div>\n    <p class=\"lede\">화면을 고치기 전에 증거부터 고정한다. DevTools로 병목을 나누고, CLI로 번들·성능·리소스 크기를 측정한다.</p>\n\n    <h3>DevTools 실전 순서</h3>\n    <pre class=\"snippet-card\"><code># 1) Performance 탭 — 느린 상호작용/로딩 원인 분리\n#    Record 시작 → 문제 동작 재현 → Stop\n#    Main thread flame chart에서 Scripting/Rendering/Painting 비중 확인\n#    Long Task(&gt;50ms) 노란 삼각형, INP 후보 interaction 클릭해 breakdown\n\n# 2) Network 탭 — waterfall로 로딩 순서 확인\n#    Disable cache 체크, throttling을 Fast 4G로 두고 새로고침\n#    LCP 이미지가 initial JS 뒤에 늦게 시작하는지, TTFB가 큰지 확인\n#    Priority 컬럼(우클릭 헤더로 표시)으로 우선순위 오지정 탐지\n\n# 3) Coverage 탭 — 안 쓰는 JS/CSS 비율\n#    Cmd+Shift+P → \"Show Coverage\" → reload → Unused Bytes 확인\n\n# 4) React DevTools Profiler — 렌더 원인\n#    Profiler 탭 → 녹화 → 상호작용 1회 → 멈춤\n#    \"Ranked\" 뷰에서 commit 비싼 컴포넌트, \"Why did this render?\" 활성화</code></pre>\n\n    <h3>빌드 · 번들 분석</h3>\n    <pre class=\"snippet-card\"><code># 프로덕션 빌드 (번들 에러/사이즈 먼저 확인)\nnpm run build\n\n# 빌드 결과를 로컬에서 프로덕션과 유사하게 서빙\nnpx serve dist          # Vite 계열\nnpx serve build         # CRA 계열\n\n# 번들에서 뭐가 큰지 시각화 (source map 필요)\nnpx source-map-explorer 'dist/**/*.js'\n\n# gzip/brotli 실제 전송 크기 확인\nnpx vite-bundle-visualizer          # Vite\nANALYZE=true npm run build          # next.js (@next/bundle-analyzer 설정 시)</code></pre>\n\n    <h3>성능 측정 (Lighthouse / Web Vitals)</h3>\n    <pre class=\"snippet-card\"><code># 성능 카테고리만 로컬 audit\nnpx lighthouse http://localhost:3000 --only-categories=performance\n\n# 헤드리스로 JSON 저장 (CI 비교용)\nnpx lighthouse http://localhost:3000 \\\n  --only-categories=performance \\\n  --output=json --output-path=./lh.json --chrome-flags=\"--headless\"\n\n# 모바일 프리셋 대신 데스크톱으로\nnpx lighthouse http://localhost:3000 --preset=desktop</code></pre>\n\n    <h3>응답 헤더 · 리소스 크기 확인</h3>\n    <pre class=\"snippet-card\"><code># 캐시/압축 헤더만 빠르게 (cache-control, etag, content-encoding)\ncurl -sI https://example.com/app.js\n\n# 압축이 실제 적용되는지 (Accept-Encoding 보내고 헤더 확인)\ncurl -sI -H \"Accept-Encoding: br,gzip\" https://example.com/app.js\n\n# 실제 전송 바이트 (전송 크기 = size_download)\ncurl -s -o /dev/null -w \"%{size_download} bytes / %{time_total}s\\n\" https://example.com/app.js\n\n# 이미지 파일 크기 확인\nls -lh public/*.{png,jpg,webp,avif} 2&gt;/dev/null</code></pre>\n\n    <h3>접근성 빠른 점검 (코드 없이 손으로)</h3>\n    <pre class=\"snippet-card\"><code># 1) Tab 키만으로 핵심 흐름 완주 — 마우스 금지\n#    포커스 순서가 시각 순서와 같은가? 갇히는 곳(trap) 없는가?\n# 2) focus visible — Tab 이동 시 포커스 링이 보이는가? (outline:none 사고)\n# 3) accessible name — 아이콘 버튼에 이름이 있는가?\n#    DevTools Elements → Accessibility 패널 → Computed Properties의 Name 확인\n# 4) 대비 — DevTools에서 텍스트 요소 클릭 → color picker의 Contrast ratio (AA≥4.5:1)</code></pre>\n\n    <table>\n      <tr><th>명령</th><th>용도</th><th>주의</th></tr>\n      <tr><td><code>npm run build</code></td><td>번들 에러·사이즈 확인</td><td>dev에선 안 잡히는 타입/트리셰이킹 문제가 여기서 남</td></tr>\n      <tr><td><code>npx serve dist</code></td><td>빌드 산출물 로컬 서빙</td><td>dev 서버가 아닌 실제 정적 파일로 검증</td></tr>\n      <tr><td><code>npx lighthouse &lt;url&gt; --only-categories=performance</code></td><td>성능 audit</td><td>lab 값 — 기기/네트워크 조건 고정해야 비교 가능</td></tr>\n      <tr><td><code>npx source-map-explorer 'dist/**/*.js'</code></td><td>번들 구성 시각화</td><td>build 시 sourcemap 켜야 함</td></tr>\n      <tr><td><code>curl -sI &lt;url&gt;</code></td><td>캐시·압축 헤더 확인</td><td>-I는 HEAD 요청 — 일부 서버는 GET과 헤더가 다름</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatfe-ch2\">\n    <div class=\"ch-head\"><span class=\"ch-code\">FE-CS-02</span><h2>판단 한 줄</h2></div>\n    <table>\n      <tr><th>선택</th><th>언제 쓰나</th><th>주의</th></tr>\n      <tr><td>CSR</td><td>로그인 뒤 내부 도구, SEO 무관, 인터랙션 중심</td><td>초기 빈 화면 + 큰 JS 번들</td></tr>\n      <tr><td>SSR</td><td>초기 표시·SEO 중요 + 사용자별 데이터</td><td>서버 비용, cache 전략, hydration 안정성</td></tr>\n      <tr><td>SSG</td><td>콘텐츠 거의 고정, CDN 빠른 제공이 핵심</td><td>데이터 변경 주기 → 재생성(ISR) 전략 필요</td></tr>\n      <tr><td>memoization</td><td>측정으로 렌더 비용/props 안정성 확인 뒤에만</td><td>측정 전 남발 = 복잡도만 증가, 병목이 네트워크면 무효</td></tr>\n      <tr><td>URL state</td><td>공유·뒤로가기·새로고침 복원 필요한 필터/검색</td><td>입력 중 값과 확정 query는 분리</td></tr>\n      <tr><td>client state</td><td>모달·탭·입력 중 값처럼 UI 즉시성 상태</td><td>공유 필요하면 URL로, 아니면 컴포넌트 로컬</td></tr>\n      <tr><td>server state</td><td>서버가 소유한 캐시 가능 비동기 데이터</td><td>UI state로 복사하지 말 것 — freshness/invalidate가 핵심</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatfe-ch3\">\n    <div class=\"ch-head\"><span class=\"ch-code\">FE-CS-03</span><h2>자주 터지는 것 · 즉시 확인</h2></div>\n    <table>\n      <tr><th>신호</th><th>왜 위험</th><th>즉시 확인</th></tr>\n      <tr><td>측정 전 <code>memo</code>/<code>useMemo</code>/<code>useCallback</code> 남발</td><td>병목이 네트워크·이미지면 효과 0, 복잡도만 증가</td><td>React Profiler로 렌더 원인, Network waterfall 먼저</td></tr>\n      <tr><td>API 응답을 컴포넌트 state로 복사</td><td>server/client 상태 혼합 → stale·동기화 버그</td><td>새로고침·탭 전환 후 값이 어긋나는지</td></tr>\n      <tr><td>hydration mismatch</td><td>서버 HTML과 client 첫 렌더 불일치 → 화면 튐</td><td>날짜·locale·random·<code>localStorage</code> 접근을 effect로 미룸</td></tr>\n      <tr><td><code>div</code>에 onClick만 붙인 가짜 버튼</td><td>키보드 도달 불가, accessible name 없음</td><td>Tab 도달 여부, semantic <code>button</code>/<code>a</code>로 교체</td></tr>\n      <tr><td>loading/empty/error/permission 상태 누락</td><td>운영 데이터에서 UI가 쉽게 깨짐</td><td>상태별 스냅샷·story, 실패 경로 2개 이상</td></tr>\n      <tr><td><code>dangerouslySetInnerHTML</code> / <code>innerHTML</code></td><td>사용자 입력이 escape 없이 DOM 실행 → XSS</td><td>sanitize, 입력 출처, CSP 확인</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatfe-ch4\">\n    <div class=\"ch-head\"><span class=\"ch-code\">FE-CS-04</span><h2>장애 증거 1카드</h2></div>\n    <div class=\"serial-card\"><span class=\"sc-label\">BROKEN SCREEN TRIAGE</span>코드부터 고치지 말고 route/role/flag → Console → Network → API/cache → hydration 순서로 증거를 고정한다. 원인 확정 전 복구는 flag off · rollback · CDN purge 중 사용자 영향이 가장 작은 것.</div>\n    <table>\n      <tr><th>순서</th><th>질문</th><th>증거</th></tr>\n      <tr><td>1</td><td>어떤 route·role·browser·viewport·flag에서만 재현?</td><td>재현 조건, session, feature flag 상태</td></tr>\n      <tr><td>2</td><td>Console error가 먼저인가?</td><td>DevTools Console stack trace, 첫 에러 시각</td></tr>\n      <tr><td>3</td><td>Network 실패가 있는가?</td><td>status code, response body, deploy SHA</td></tr>\n      <tr><td>4</td><td>API contract 변경 또는 cache stale인가?</td><td>response schema, etag/cache-control</td></tr>\n      <tr><td>5</td><td>hydration·date/locale/random·browser-only API 차이?</td><td>SSR log, client stack, hydration warning</td></tr>\n    </table>\n    <div class=\"callout warn\"><span class=\"co-label\">복구/중단</span><p>영향 범위와 데이터 변경 여부부터 확인. 데이터를 바꾸지 않는 flag off를 우선, 배포 회귀면 rollback, 정적 자산 stale이면 CDN purge. 원인 미확정 상태로 hotfix 배포 금지.</p></div>\n  </section>\n\n<section id=\"doc-cheatbe\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>Backend</h2></div>\n</section>\n\n<section id=\"cheatbe-ch1\">\n    <div class=\"ch-head\"><span class=\"ch-code\">BE-CS-01</span><h2>핵심 명령·스니펫</h2></div>\n\n    <h3>요청 찌르기 (curl / HTTPie)</h3>\n    <pre class=\"snippet-card\"><code># 헤더까지 보기 — status, 응답 헤더 확인 (가장 많이 씀)\ncurl -i https://api.example.com/orders/42\n\n# 상태코드만 뽑기\ncurl -s -o /dev/null -w '%{http_code}\\n' https://api.example.com/health\n\n# POST + JSON + 멱등키 (재시도 안전)\ncurl -X POST \\\n  -H 'Content-Type: application/json' \\\n  -H 'Idempotency-Key: 8f14e45f-ceea-467a-9c3d-1b2c3d4e5f60' \\\n  -d '{\"amount\":1000,\"currency\":\"KRW\"}' \\\n  https://api.example.com/payments\n\n# Bearer 토큰 인증\ncurl -H 'Authorization: Bearer &lt;token&gt;' https://api.example.com/me\n\n# 타임/트레이스 프로파일 (DNS→connect→TTFB→total)\ncurl -s -o /dev/null \\\n  -w 'dns:%{time_namelookup} conn:%{time_connect} ttfb:%{time_starttransfer} total:%{time_total}\\n' \\\n  https://api.example.com/orders</code></pre>\n    <pre class=\"snippet-card\"><code># HTTPie — 키=값이면 자동 JSON, 사람이 읽기 좋게 출력\nhttp POST api.example.com/payments amount=1000 currency=KRW \\\n  Idempotency-Key:8f14e45f-ceea-467a Authorization:'Bearer &lt;token&gt;'\n\n# 헤더만 보기\nhttp --headers GET api.example.com/orders/42</code></pre>\n\n    <h3>응답 파싱 (jq)</h3>\n    <pre class=\"snippet-card\"><code># 특정 필드\ncurl -s api.example.com/orders/42 | jq '.status'\n\n# 배열에서 골라 뽑기\ncurl -s api.example.com/orders | jq '.data[] | {id, status}'\n\n# 조건 필터 (실패 건만)\ncurl -s api.example.com/orders | jq '.data[] | select(.status==\"FAILED\")'\n\n# 개수 세기\ncurl -s api.example.com/orders | jq '.data | length'</code></pre>\n\n    <h3>부하 테스트</h3>\n    <pre class=\"snippet-card\"><code># hey — 10초 동안 동시 50 (p50/p95/p99 히스토그램)\nhey -z 10s -c 50 https://api.example.com/orders\n\n# hey — 총 1000요청, POST + body\nhey -n 1000 -c 50 -m POST -T 'application/json' \\\n  -d '{\"amount\":1000}' https://api.example.com/payments\n\n# ApacheBench — 총 1000요청, 동시 50\nab -n 1000 -c 50 https://api.example.com/orders</code></pre>\n\n    <h3>JWT 디코드 (payload 까보기)</h3>\n    <pre class=\"snippet-card\"><code># 2번째 파트(payload)만 base64 디코드 → exp, sub, role 확인\necho &lt;jwt&gt; | cut -d. -f2 | base64 -d | jq\n\n# padding 에러 나면 base64 대신 (macOS)\necho &lt;jwt&gt; | cut -d. -f2 | base64 -D 2&gt;/dev/null | jq</code></pre>\n\n    <h3>로그 추적</h3>\n    <pre class=\"snippet-card\"><code># requestId로 한 요청의 전 구간 따라가기\ngrep 'req-8f14e45f' app.log\n\n# 5xx만 실시간\ntail -f app.log | grep -E '\"status\":5[0-9]{2}'\n\n# errorCode별 집계 top\ngrep -oE '\"errorCode\":\"[^\"]+\"' app.log | sort | uniq -c | sort -rn | head</code></pre>\n\n    <table>\n      <tr><th>명령</th><th>용도</th><th>주의</th></tr>\n      <tr><td><code>curl -i &lt;url&gt;</code></td><td>status·헤더 확인, 첫 진단</td><td><code>-s</code>로 progress 끄기</td></tr>\n      <tr><td><code>curl -sS -f &lt;url&gt;</code></td><td>스크립트용: 4xx/5xx면 exit≠0</td><td><code>-f</code>는 body 안 보여줌</td></tr>\n      <tr><td><code>curl -L &lt;url&gt;</code></td><td>redirect 따라가기</td><td>POST가 GET으로 바뀔 수 있음</td></tr>\n      <tr><td><code>jq -r '.token'</code></td><td>따옴표 없는 raw 값 추출</td><td>파이프 대입 시 필수</td></tr>\n      <tr><td><code>hey -z 10s -c 50</code></td><td>p95/p99 지연 측정</td><td>prod 대상 금지</td></tr>\n      <tr><td><code>ab -n 1000 -c 50</code></td><td>간단 처리량 측정</td><td>keep-alive는 <code>-k</code></td></tr>\n    </table>\n    <div class=\"callout warn\"><span class=\"co-label\">주의</span><p>부하 명령(<code>hey</code>, <code>ab</code>)은 staging/local에만. prod에 걸면 self-DoS. JWT 디코드는 서명 검증이 아니라 payload 열람일 뿐이니 신뢰 판단에 쓰지 말 것.</p></div>\n  </section>\n\n  <section id=\"cheatbe-ch2\">\n    <div class=\"ch-head\"><span class=\"ch-code\">BE-CS-02</span><h2>판단 한 줄</h2></div>\n    <table>\n      <tr><th>선택</th><th>언제 쓰나</th><th>주의</th></tr>\n      <tr><td>Session</td><td>즉시 폐기·서버 제어가 중요할 때</td><td>scale-out 시 공용 session store 필요</td></tr>\n      <tr><td>JWT</td><td>stateless·분산 검증이 중요할 때</td><td>즉시 폐기 어려움 → 짧은 만료 + refresh</td></tr>\n      <tr><td>RBAC</td><td>역할이 명확하고 조직이 단순할 때</td><td>예외 늘면 role explosion</td></tr>\n      <tr><td>ABAC</td><td>소유자·조직·상태 등 속성 기반 판단 필요</td><td>정책 테스트·설명가능성 확보</td></tr>\n      <tr><td>Optimistic lock</td><td>충돌이 드물고 재시도 UX가 가능할 때</td><td>version 충돌 시 재시도 흐름 필요</td></tr>\n      <tr><td>Pessimistic lock</td><td>충돌 비용이 크고 직렬 처리가 필요할 때</td><td>lock wait·deadlock 관리</td></tr>\n      <tr><td>Sync 호출</td><td>결과가 즉시 필요하고 빠를 때</td><td>외부 장애가 요청 pool로 전파</td></tr>\n      <tr><td>Queue(async)</td><td>부하 평탄화·재시도·장애 격리가 우선일 때</td><td>중복 소비·순서 별도 설계</td></tr>\n    </table>\n    <div class=\"callout gm\"><span class=\"co-label\">쿠키 옵션</span><p>인증 쿠키는 <code>HttpOnly</code>(JS 접근 차단) + <code>Secure</code>(HTTPS 전용) + <code>SameSite</code>(CSRF 완화) 세 개 세트로. <code>SameSite=Lax</code>가 기본 권장, 크로스사이트 전송이 꼭 필요하면 <code>SameSite=None; Secure</code>.</p></div>\n  </section>\n\n  <section id=\"cheatbe-ch3\">\n    <div class=\"ch-head\"><span class=\"ch-code\">BE-CS-03</span><h2>자주 터지는 것 · 즉시 확인</h2></div>\n    <table>\n      <tr><th>신호</th><th>왜 위험</th><th>즉시 확인</th></tr>\n      <tr><td>프론트 validation 있으니 server validation 생략</td><td>클라이언트는 신뢰 경계 밖 — API 직접 호출로 우회</td><td>server 측 형식·범위·상태전이 검증 존재 여부</td></tr>\n      <tr><td>권한 검사를 controller 일부 경로에만</td><td>다른 진입점으로 우회 경로 생김</td><td>service/data layer 기준 authorization + resource ownership</td></tr>\n      <tr><td>POST 재시도로 중복 생성/결제</td><td>timeout·새로고침·모바일 재시도는 정상 조건</td><td><b>idempotency</b> key + unique constraint + 재시도 응답 정책</td></tr>\n      <tr><td>transaction 안에서 외부 API 호출</td><td>lock 시간이 외부 장애 시간만큼 늘어남</td><td>외부호출을 경계 밖으로 / outbox·사후 보상</td></tr>\n      <tr><td>에러를 전부 500으로 뭉갬</td><td>클라이언트가 재시도/수정/권한요청을 구분 못함</td><td>status + machine-readable code + retryable 여부</td></tr>\n      <tr><td>로그에 requestId/actor 없음</td><td>장애 때 한 요청을 추적 불가</td><td>requestId·actor·target·result 로깅(PII·secret 제외)</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatbe-ch4\">\n    <div class=\"ch-head\"><span class=\"ch-code\">BE-CS-04</span><h2>장애 증거 1카드</h2></div>\n    <div class=\"serial-card\"><span class=\"sc-label\">API INCIDENT TRIAGE</span>\n      1. 어떤 route·status·errorCode·requestId가 늘었나 (증거 확보)<br>\n      2. 상류 timeout인가 slow query인가 (upstream span vs DB metric)<br>\n      3. 이 요청이 재시도 안전한가 (idempotency 있으면 재시도 OK)<br>\n      4. 사용자 영향 범위는 (특정 tenant/actor/전체)\n    </div>\n    <table>\n      <tr><th>순서</th><th>질문</th><th>증거</th></tr>\n      <tr><td>1</td><td>어떤 route·status·errorCode·requestId가 증가했나?</td><td>gateway/app log, dashboard, <code>grep errorCode</code></td></tr>\n      <tr><td>2</td><td>상류(외부 API) timeout인가, 내부 slow query인가?</td><td>trace span, upstream status vs DB slow query log</td></tr>\n      <tr><td>3</td><td>이 요청은 재시도해도 안전한가?</td><td>메서드(GET/PUT), idempotency key 유무</td></tr>\n      <tr><td>4</td><td>사용자 영향 범위는? (특정 tenant/전체)</td><td>actor·tenant 분포, 성공/실패 비율</td></tr>\n    </table>\n    <div class=\"callout risk\"><span class=\"co-label\">복구/중단 기준</span><p>중복 생성·결제가 진행 중이면 쓰기 경로를 먼저 <b>중단</b>(flag off)하고 affected row를 식별한다. 단일 release 회귀면 rollback, 상류 장애면 traffic shedding·retry 축소로 격리. data migration이 얽힌 변경은 rollback 전에 정합성부터 확인.</p></div>\n  </section>\n\n<section id=\"doc-cheatdb\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>Database</h2></div>\n</section>\n\n<section id=\"cheatdb-ch1\">\n    <div class=\"ch-head\"><span class=\"ch-code\">DB-CS-01</span><h2>핵심 명령·스니펫</h2></div>\n\n    <p class=\"lede\">실행계획 → 인덱스 → 락 → 통계 순으로 본다. 아래 스니펫은 대부분 복붙 후 테이블/컬럼명만 바꾸면 된다.</p>\n\n    <h3>실행계획 (EXPLAIN)</h3>\n    <pre class=\"snippet-card\"><code># 실제 실행 + 버퍼까지 (진짜 느린 원인 찾을 때 이거)\nEXPLAIN (ANALYZE, BUFFERS) SELECT ... FROM orders WHERE user_id = 42;\n\n# 계획만 (쿼리 실제 실행 안 함, 안전)\nEXPLAIN SELECT ... FROM orders WHERE user_id = 42;\n\n# 포맷 옵션\nEXPLAIN (ANALYZE, BUFFERS, FORMAT JSON) SELECT ...;\n\n# MySQL:  EXPLAIN ANALYZE SELECT ...;   /  EXPLAIN FORMAT=JSON SELECT ...;\n# MySQL 8: EXPLAIN ANALYZE 는 실제 실행됨 (Postgres와 동일 주의)</code></pre>\n    <div class=\"callout warn\"><span class=\"co-label\">주의</span><p><code>ANALYZE</code>는 쿼리를 <b>실제로 실행</b>한다. UPDATE/DELETE/INSERT에 붙이면 데이터가 바뀐다. 쓰기 쿼리는 <code>BEGIN; EXPLAIN (ANALYZE) ...; ROLLBACK;</code> 로 감싼다.</p></div>\n\n    <h3>인덱스 확인·생성</h3>\n    <pre class=\"snippet-card\"><code># 테이블의 인덱스/컬럼/제약 한눈에 (psql)\n\\d orders\n\\d+ orders\n\n# 인덱스 목록만\nSELECT * FROM pg_indexes WHERE tablename = 'orders';\n\n# 인덱스 정의 + 크기\nSELECT indexname, indexdef FROM pg_indexes WHERE tablename = 'orders';\nSELECT pg_size_pretty(pg_relation_size('idx_orders_user_id'));\n\n# 락 없이 인덱스 생성 (운영 테이블은 반드시 CONCURRENTLY)\nCREATE INDEX CONCURRENTLY idx_orders_user_id ON orders (user_id);\n\n# 복합 인덱스 (컬럼 순서 = 좌측 우선 규칙)\nCREATE INDEX idx_orders_user_created ON orders (user_id, created_at DESC);\n\n# 부분 인덱스 (조건 걸린 행만 색인 → 작고 빠름)\nCREATE INDEX idx_orders_active ON orders (user_id) WHERE status = 'ACTIVE';\n\n# 안 쓰이는 인덱스 찾기 (idx_scan = 0)\nSELECT relname, indexrelname, idx_scan\nFROM pg_stat_user_indexes ORDER BY idx_scan ASC;</code></pre>\n    <div class=\"callout warn\"><span class=\"co-label\">주의</span><p><code>CREATE INDEX CONCURRENTLY</code>는 transaction block 안에서 못 쓴다. 실패하면 <b>INVALID 인덱스</b>가 남으니 <code>DROP INDEX</code> 후 재시도. MySQL은 <code>ALGORITHM=INPLACE, LOCK=NONE</code>.</p></div>\n\n    <h3>블로킹 락 / 활성 쿼리</h3>\n    <pre class=\"snippet-card\"><code># 지금 잡혀 있는 락 (누가 무엇을)\nSELECT * FROM pg_locks WHERE NOT granted;\n\n# 무엇이 무엇을 막는지 (blocking → blocked) — 가장 실전적\nSELECT blocked.pid   AS blocked_pid,\n       blocking.pid  AS blocking_pid,\n       blocked.query AS blocked_query,\n       blocking.query AS blocking_query\nFROM pg_stat_activity blocked\nJOIN pg_stat_activity blocking\n  ON blocking.pid = ANY(pg_blocking_pids(blocked.pid))\nWHERE blocked.wait_event_type = 'Lock';\n\n# 오래 도는 쿼리 (5초 이상)\nSELECT pid, now() - query_start AS runtime, state, query\nFROM pg_stat_activity\nWHERE state != 'idle' AND now() - query_start &gt; interval '5 seconds'\nORDER BY runtime DESC;\n\n# 문제 세션 죽이기 (cancel = 쿼리만, terminate = 연결까지)\nSELECT pg_cancel_backend(&lt;pid&gt;);\nSELECT pg_terminate_backend(&lt;pid&gt;);</code></pre>\n    <div class=\"callout warn\"><span class=\"co-label\">주의</span><p><code>pg_terminate_backend</code>는 연결을 끊는다. 트랜잭션 중이면 rollback된다. 운영에서 남의 세션 죽이기 전에 <b>무슨 쿼리인지</b> 반드시 확인.</p></div>\n\n    <h3>느린 쿼리 통계 (pg_stat_statements)</h3>\n    <pre class=\"snippet-card\"><code># 확장 켜기 (한 번, 재시작 필요할 수 있음)\nCREATE EXTENSION IF NOT EXISTS pg_stat_statements;\n\n# 총 소요시간 상위 쿼리 (범인 후보)\nSELECT query, calls, total_exec_time, mean_exec_time, rows\nFROM pg_stat_statements\nORDER BY total_exec_time DESC LIMIT 20;\n\n# 평균 느린 쿼리\nSELECT query, calls, mean_exec_time\nFROM pg_stat_statements ORDER BY mean_exec_time DESC LIMIT 20;\n\n# 통계 리셋\nSELECT pg_stat_statements_reset();\n\n# MySQL: SELECT * FROM sys.statement_analysis ORDER BY total_latency DESC;\n#        performance_schema.events_statements_summary_by_digest</code></pre>\n\n    <h3>통계·정리 (VACUUM / ANALYZE)</h3>\n    <pre class=\"snippet-card\"><code># 통계 갱신 (실행계획이 이상하면 제일 먼저)\nVACUUM (ANALYZE) orders;\nANALYZE orders;              -- 통계만, 락 가벼움\n\n# dead tuple / 마지막 vacuum 시점 확인\nSELECT relname, n_dead_tup, last_autovacuum, last_analyze\nFROM pg_stat_user_tables ORDER BY n_dead_tup DESC;\n\n# 테이블/인덱스 크기\nSELECT pg_size_pretty(pg_total_relation_size('orders'));</code></pre>\n    <div class=\"callout risk\"><span class=\"co-label\">위험</span><p><code>VACUUM FULL</code>은 테이블을 <b>ACCESS EXCLUSIVE 락</b>으로 완전히 잠그고 재작성한다. 대형 테이블에 운영 중 실행 금지. 공간 회수는 <code>pg_repack</code> 고려.</p></div>\n\n    <h3>안전한 마이그레이션 패턴 (NOT NULL 컬럼 추가)</h3>\n    <pre class=\"snippet-card\"><code># 1) nullable로 먼저 추가 (즉시, 락 짧음)\nALTER TABLE orders ADD COLUMN region text;\n\n# 2) 배치로 backfill (한 번에 UPDATE 금지 — 락+WAL 폭증)\nUPDATE orders SET region = 'KR'\nWHERE id BETWEEN 1 AND 10000 AND region IS NULL;\n-- id 범위 올려가며 반복 / 사이에 sleep\n\n# 3) 기본값·제약은 backfill 끝난 뒤\nALTER TABLE orders ALTER COLUMN region SET DEFAULT 'KR';\n\n# 4) NOT NULL 은 CHECK로 먼저 검증 후 승격 (풀스캔 락 회피)\nALTER TABLE orders ADD CONSTRAINT region_nn CHECK (region IS NOT NULL) NOT VALID;\nALTER TABLE orders VALIDATE CONSTRAINT region_nn;   -- 락 가벼움\nALTER TABLE orders ALTER COLUMN region SET NOT NULL;</code></pre>\n    <div class=\"callout warn\"><span class=\"co-label\">주의</span><p>대형 테이블 <code>ALTER TABLE</code>은 <b>ACCESS EXCLUSIVE 락</b>을 잡는다. 배포 시 <code>SET lock_timeout = '3s';</code> 를 먼저 걸어 락 대기가 서비스를 막지 않게 한다.</p></div>\n\n    <h3>psql 자주 쓰는 것</h3>\n    <table>\n      <tr><th>명령</th><th>용도</th><th>주의</th></tr>\n      <tr><td><code>\\dt</code></td><td>테이블 목록</td><td><code>\\dt+</code> 는 크기까지</td></tr>\n      <tr><td><code>\\d+ orders</code></td><td>컬럼·인덱스·제약·크기 전체</td><td>디버깅 첫 명령</td></tr>\n      <tr><td><code>\\di</code></td><td>인덱스 목록</td><td>—</td></tr>\n      <tr><td><code>\\timing</code></td><td>쿼리 실행시간 표시 on/off</td><td>체감 측정용</td></tr>\n      <tr><td><code>\\x</code></td><td>세로 출력 (넓은 행)</td><td>EXPLAIN 볼 때 편함</td></tr>\n      <tr><td><code>\\l</code></td><td>DB 목록</td><td>—</td></tr>\n      <tr><td><code>\\du</code></td><td>role/권한 목록</td><td>—</td></tr>\n      <tr><td><code>\\e</code></td><td>에디터로 쿼리 편집</td><td>긴 쿼리에</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatdb-ch2\">\n    <div class=\"ch-head\"><span class=\"ch-code\">DB-CS-02</span><h2>판단 한 줄</h2></div>\n\n    <table>\n      <tr><th>선택</th><th>언제 쓰나</th><th>주의</th></tr>\n      <tr><td>B-tree 인덱스</td><td>등호·범위·정렬·<code>LIKE 'x%'</code> 대부분의 기본</td><td><code>LIKE '%x'</code> 선행 와일드카드엔 안 먹음</td></tr>\n      <tr><td>Partial 인덱스</td><td>일부 행만 자주 조회 (예: status='ACTIVE')</td><td>WHERE 조건이 쿼리와 일치해야 사용됨</td></tr>\n      <tr><td>Composite 인덱스</td><td>여러 컬럼 AND 조건이 함께 자주 옴</td><td>좌측 우선 — 컬럼 순서가 곧 사용 범위</td></tr>\n      <tr><td>Covering 인덱스</td><td>인덱스만으로 SELECT 컬럼 다 충당 (<code>INCLUDE</code>)</td><td>Index Only Scan 노림, 인덱스 커짐</td></tr>\n      <tr><td>Normalization</td><td>쓰기 정합성이 중요한 OLTP, 중복 제거</td><td>조인 늘어 읽기 비용 증가</td></tr>\n      <tr><td>Denormalization</td><td>읽기 폭증·리포트, 조인 비용이 병목</td><td>중복 갱신 로직·정합성 책임이 앱으로 옴</td></tr>\n      <tr><td>OLTP 튜닝</td><td>짧고 잦은 트랜잭션 → 인덱스·락 최소화</td><td>인덱스 과다는 쓰기 느리게 함</td></tr>\n      <tr><td>분석 쿼리</td><td>대량 집계 → 풀스캔·병렬·partition이 오히려 유리</td><td>OLTP 인덱스 전략과 반대일 수 있음</td></tr>\n    </table>\n\n    <h3>Transaction isolation level</h3>\n    <div class=\"glossary\">\n      <div class=\"g-row\"><div class=\"g-term\"><b>Read Committed</b><span>기본값(PG/Oracle)</span></div><div class=\"g-def\">커밋된 것만 읽음. non-repeatable read 허용. 대부분의 앱 기본으로 충분.</div></div>\n      <div class=\"g-row\"><div class=\"g-term\"><b>Repeatable Read</b><span>MySQL 기본</span></div><div class=\"g-def\">트랜잭션 내 같은 읽기 보장. PG에선 phantom도 막음. 재시도(serialization error) 필요할 수 있음.</div></div>\n      <div class=\"g-row\"><div class=\"g-term\"><b>Serializable</b><span>가장 엄격</span></div><div class=\"g-def\">순차 실행처럼 보장. 정합성 최상, 대신 conflict 시 rollback 잦음 → 재시도 로직 필수.</div></div>\n    </div>\n  </section>\n\n  <section id=\"cheatdb-ch3\">\n    <div class=\"ch-head\"><span class=\"ch-code\">DB-CS-03</span><h2>자주 터지는 것 · 즉시 확인</h2></div>\n    <table>\n      <tr><th>신호</th><th>왜 위험</th><th>즉시 확인</th></tr>\n      <tr><td>N+1 쿼리</td><td>목록 1 + 항목당 1 → 수백 쿼리, 지연 폭증</td><td>ORM 로그의 반복 SELECT, <code>JOIN</code>/eager fetch/<code>IN</code> 배치로 전환</td></tr>\n      <tr><td>함수로 감싼 컬럼<br><code>WHERE lower(email)=...</code></td><td>인덱스 미사용 → 풀스캔</td><td>EXPLAIN에 Seq Scan, expression index <code>ON t(lower(email))</code> 필요</td></tr>\n      <tr><td>대형 테이블 DDL</td><td><code>ALTER/CREATE INDEX</code>가 ACCESS EXCLUSIVE 락 → 서비스 정지</td><td><code>CONCURRENTLY</code>/<code>NOT VALID</code> 여부, <code>lock_timeout</code> 설정</td></tr>\n      <tr><td>무제한 SELECT</td><td><code>LIMIT</code>/<code>WHERE</code> 없는 조회 → 메모리·전송 폭발</td><td>pagination(keyset), 페이지 크기 상한 존재?</td></tr>\n      <tr><td>마이그레이션 rollback 부재</td><td>실패 시 되돌릴 수 없어 배포가 막힘</td><td>down 스크립트, 배포 전 트랜잭션 감싸기 여부</td></tr>\n      <tr><td>암묵적 형변환<br><code>id = '42'</code></td><td>text↔int 캐스팅 → 인덱스 무력화</td><td>파라미터 타입 일치, EXPLAIN에 cast 흔적</td></tr>\n      <tr><td>낮은 선택도 인덱스</td><td><code>status</code>처럼 값 몇 개뿐 → 인덱스 무시됨</td><td>partial/composite로 재설계, 카디널리티 확인</td></tr>\n      <tr><td>SELECT * 대량 컬럼</td><td>불필요 컬럼·TOAST 로드로 I/O 낭비, covering 불가</td><td>필요한 컬럼만 명시</td></tr>\n      <tr><td>긴 트랜잭션</td><td>락 오래 잡고 VACUUM 방해(dead tuple 누적)</td><td><code>pg_stat_activity</code>의 idle in transaction 확인</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatdb-ch4\">\n    <div class=\"ch-head\"><span class=\"ch-code\">DB-CS-04</span><h2>장애 증거 1카드</h2></div>\n    <div class=\"serial-card\"><span class=\"sc-label\">SLOW QUERY FIRST LOOK</span>\n      1. <b>EXPLAIN (ANALYZE, BUFFERS)</b> 로 실제 실행계획을 뜬다.<br>\n      2. <b>인덱스 사용 여부</b> — Seq Scan인가 Index Scan인가. 예상 인덱스가 왜 안 먹나.<br>\n      3. <b>row 수 / 버퍼</b> — estimated vs actual rows 괴리(통계 낡음?), read 버퍼량.<br>\n      4. <b>lock 대기</b> — 느린 게 아니라 막힌 것일 수 있다. <code>pg_blocking_pids</code> 확인.<br>\n      5. 그다음 <b>쿼리 → 인덱스 → 스키마</b> 순으로 고친다. 스키마 변경이 가장 무겁고 마지막.\n    </div>\n    <table>\n      <tr><th>순서</th><th>질문</th><th>증거</th></tr>\n      <tr><td>1</td><td>실제로 무엇이 느린가</td><td><code>EXPLAIN (ANALYZE, BUFFERS)</code> 출력, 가장 비싼 노드</td></tr>\n      <tr><td>2</td><td>인덱스가 쓰였나</td><td>Index Scan / Seq Scan / Bitmap 여부, <code>\\d orders</code> 인덱스 목록</td></tr>\n      <tr><td>3</td><td>추정과 실제가 맞나</td><td>estimated vs actual rows, <code>last_analyze</code> 시점</td></tr>\n      <tr><td>4</td><td>느린 게 아니라 막힌 건 아닌가</td><td><code>pg_stat_activity</code> wait_event, <code>pg_blocking_pids</code></td></tr>\n      <tr><td>5</td><td>반복적으로 비싼가</td><td><code>pg_stat_statements</code> total/mean_exec_time 순위</td></tr>\n    </table>\n    <div class=\"callout gm\"><span class=\"co-label\">복구·중단 기준</span><p>인덱스 추가는 <code>CONCURRENTLY</code>로 무중단. 원인이 특정 세션의 blocking이면 <code>pg_cancel_backend</code>로 완화. DDL이 락으로 서비스를 막고 있으면 즉시 취소하고 배치·CONCURRENTLY로 재설계 — <b>운영 중 대형 테이블 락은 롤백이 최우선</b>.</p></div>\n  </section>\n\n<section id=\"doc-cheatnet\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>Network</h2></div>\n</section>\n\n<section id=\"cheatnet-ch1\">\n    <div class=\"ch-head\"><span class=\"ch-code\">NW-CS-01</span><h2>핵심 명령·스니펫</h2></div>\n\n    <h3>DNS 해석</h3>\n    <pre class=\"snippet-card\"><code>dig +short example.com          # A record만 간결하게\ndig example.com A               # A record + TTL + 권위 응답\ndig example.com CNAME           # CNAME chain 확인\ndig +short example.com @1.1.1.1 # 특정 resolver로 질의 (내부/외부 비교)\ndig +trace example.com          # root부터 authoritative까지 추적\nnslookup example.com            # 빠른 확인 (레거시, 출력은 dig가 정확)</code></pre>\n\n    <h3>연결·HTTP</h3>\n    <pre class=\"snippet-card\"><code>nc -vz example.com 443          # TCP 도달성만 빠르게 (succeeded/refused/timeout)\ncurl -v https://example.com     # DNS→connect→TLS→HTTP 전 흐름 한 번에\ncurl -vkI https://example.com/  # 헤더만 (-k: 인증서 무시, -I: HEAD)\ncurl -w 'dns:%{time_namelookup} conn:%{time_connect} tls:%{time_appconnect} total:%{time_total}\\n' -o /dev/null -s https://example.com\n                                # 단계별 소요 시간 분해 (병목 위치 특정)</code></pre>\n\n    <h3>리슨 소켓·경로</h3>\n    <pre class=\"snippet-card\"><code>ss -tlnp                        # 서버에서 listening TCP 소켓 (bind address:port)\nss -tnp state established        # 현재 맺힌 연결\ntraceroute example.com          # hop별 경로 추정 (방화벽/ICMP로 불완전)\nmtr example.com                 # traceroute + ping 연속 (packet loss/hop 관찰)</code></pre>\n\n    <h3>TLS·패킷</h3>\n    <pre class=\"snippet-card\"><code>openssl s_client -connect example.com:443 -servername example.com\n                                # SNI 지정 handshake, chain/SAN/만료 확인\nopenssl s_client -connect example.com:443 -servername example.com 2&gt;&amp;1 | openssl x509 -noout -dates\n                                # 인증서 만료일만 추출\nsudo tcpdump -ni any port 443   # 443 패킷 실시간 (인터페이스 any, 이름 해석 끔)</code></pre>\n\n    <table>\n      <tr><th>명령</th><th>용도</th><th>주의</th></tr>\n      <tr><td><code>dig +short example.com</code></td><td>A record 간결 확인</td><td>캐시된 값일 수 있음, TTL은 안 보임</td></tr>\n      <tr><td><code>nc -vz host 443</code></td><td>TCP 도달성</td><td>HTTP 이전 계층만, 앱 정상 여부 아님</td></tr>\n      <tr><td><code>curl -v https://host</code></td><td>전 계층 흐름</td><td>어느 단계에서 멈추는지 로그를 읽어라</td></tr>\n      <tr><td><code>ss -tlnp</code></td><td>listen 소켓</td><td>root 아니면 프로세스명 안 보일 수 있음</td></tr>\n      <tr><td><code>openssl s_client -connect host:443 -servername host</code></td><td>TLS handshake</td><td><code>-servername</code> 빼면 SNI 미전송으로 다른 인증서</td></tr>\n    </table>\n\n    <div class=\"callout warn\"><span class=\"co-label\">주의</span><p><code>tcpdump</code>는 <code>sudo</code> 필요, 트래픽에 PII/토큰이 캡처될 수 있으니 파일 저장·공유 주의. <code>traceroute</code>/<code>mtr</code>는 방화벽·ICMP rate limit로 hop이 <code>*</code>로 비어도 정상일 수 있어 경로 단정 금지.</p></div>\n  </section>\n\n  <section id=\"cheatnet-ch2\">\n    <div class=\"ch-head\"><span class=\"ch-code\">NW-CS-02</span><h2>판단 한 줄</h2></div>\n    <table>\n      <tr><th>선택</th><th>언제 쓰나</th><th>주의</th></tr>\n      <tr><td>TCP</td><td>순서·신뢰성 필요 (HTTP, DB, gRPC)</td><td>handshake·재전송 지연, head-of-line blocking</td></tr>\n      <tr><td>UDP</td><td>저지연·손실 허용 (DNS, QUIC, 실시간)</td><td>재전송·순서 보장 없음, 앱이 책임</td></tr>\n      <tr><td>A / AAAA</td><td>이름 → IPv4 / IPv6</td><td>AAAA만 있고 IPv6 경로 없으면 timeout</td></tr>\n      <tr><td>CNAME</td><td>이름 → 다른 이름 (별칭)</td><td>chain이 길면 지연, zone apex엔 못 씀</td></tr>\n      <tr><td>TLS 1.2 vs 1.3</td><td>1.3 우선 (RTT 적고 안전)</td><td>구형 클라이언트/미들박스는 1.2 fallback</td></tr>\n      <tr><td>SNI</td><td>한 IP에 여러 인증서일 때 hostname 전달</td><td>IP 직접 접속·SNI 누락 시 잘못된 인증서</td></tr>\n      <tr><td>timeout</td><td>SYN에 응답 없음 → drop/방화벽/route</td><td>서버 도달 자체를 의심</td></tr>\n      <tr><td>connection refused</td><td>RST 응답 → 호스트는 있는데 포트 안 들음</td><td>앱 미기동, 잘못된 포트, localhost bind</td></tr>\n      <tr><td>no route to host</td><td>경로 없음 → route table/subnet</td><td>방화벽 drop과 구분, L3 문제</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatnet-ch3\">\n    <div class=\"ch-head\"><span class=\"ch-code\">NW-CS-03</span><h2>자주 터지는 것 · 즉시 확인</h2></div>\n    <table>\n      <tr><th>신호</th><th>왜 위험</th><th>즉시 확인</th></tr>\n      <tr><td>ping 성공만으로 정상 판단</td><td>ICMP 성공과 TCP/TLS/HTTP 성공은 별개</td><td><code>nc -vz host port</code>, <code>curl -v</code>, 서버 access log</td></tr>\n      <tr><td>return path/방화벽 미확인</td><td>outbound만 열고 응답 경로·inbound 규칙을 안 봄</td><td>양쪽 firewall, route table, stateless 장비 양방향 rule</td></tr>\n      <tr><td>DNS 캐시/TTL 간과</td><td>변경했는데 캐시된 옛 record로 접속</td><td><code>dig host @resolver</code>로 내부·외부 비교, TTL 확인</td></tr>\n      <tr><td>TLS SNI/체인 누락</td><td>SNI 미전송·중간 인증서 누락으로 handshake 실패</td><td><code>openssl s_client -connect host:443 -servername host</code></td></tr>\n      <tr><td>출발지·목적지·포트 미특정</td><td>\"열었다\"만으로는 검증 불가, 장애 시간 증가</td><td>source/dest/port/direction 4개를 명령에 박아 재현</td></tr>\n      <tr><td>localhost bind</td><td>0.0.0.0 대신 127.0.0.1 bind로 외부 연결 거부</td><td><code>ss -tlnp</code>로 bind address 확인</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatnet-ch4\">\n    <div class=\"ch-head\"><span class=\"ch-code\">NW-CS-04</span><h2>장애 증거 1카드</h2></div>\n    <div class=\"serial-card\"><span class=\"sc-label\">L3-L7 TRIAGE</span>1. DNS — <code>dig +short host @resolver</code>로 이름 해석 확인 (내부/외부 비교)<br>2. TCP — <code>nc -vz host port</code>로 도달성 확인<br>3. TLS — <code>openssl s_client -connect host:443 -servername host</code>로 chain/SAN 확인<br>4. HTTP — <code>curl -v https://host/path</code>로 status/redirect/header 확인<br>5. 서버 — <code>ss -tlnp</code>로 bind, access log/target health 대조</div>\n    <table>\n      <tr><th>순서</th><th>질문</th><th>증거</th></tr>\n      <tr><td>DNS</td><td>기대 IP로 해석되나, resolver별로 같나</td><td><code>dig</code> record + TTL, 내부/외부 일치</td></tr>\n      <tr><td>TCP</td><td>포트까지 패킷이 닿나</td><td><code>nc -vz</code> succeeded (아니면 refused/timeout 구분)</td></tr>\n      <tr><td>TLS</td><td>인증서 신뢰·hostname 일치하나</td><td><code>openssl</code> chain 검증, SAN에 host 포함, 미만료</td></tr>\n      <tr><td>HTTP</td><td>앱이 응답하나, 어느 계층 오류인가</td><td><code>curl -v</code> status code, request id, upstream log</td></tr>\n    </table>\n    <div class=\"callout warn\"><span class=\"co-label\">중단 기준</span><p>출발지·목적지·포트·방향을 특정하기 전엔 \"네트워크 정상\"으로 판단 금지. 한 계층에서 증거가 확정되면 다음 계층으로 내려가고, 상위 계층 수정 전 하위 계층 증거를 먼저 확보한다.</p></div>\n  </section>\n\n<section id=\"doc-cheatdevops\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>DevOps</h2></div>\n</section>\n\n<section id=\"cheatdevops-ch1\">\n    <div class=\"ch-head\"><span class=\"ch-code\">DO-CS-01</span><h2>핵심 명령·스니펫</h2></div>\n\n    <h3>kubectl — 상태 확인</h3>\n    <pre class=\"snippet-card\"><code>kubectl get pods -o wide                 # 노드/IP까지 한눈에\nkubectl get pods -w                      # 상태 변화 실시간 watch\nkubectl logs -f &lt;pod&gt;                    # 로그 follow\nkubectl logs &lt;pod&gt; --previous            # 크래시 직전 컨테이너 로그\nkubectl describe pod &lt;pod&gt;               # 이벤트/스케줄링 실패 원인\nkubectl get events --sort-by=.lastTimestamp   # 최근 이벤트 시간순\nkubectl top pod                          # 실시간 CPU/mem (metrics-server 필요)</code></pre>\n\n    <h3>배포 상태·롤아웃</h3>\n    <pre class=\"snippet-card\"><code>kubectl rollout status deploy/&lt;x&gt;       # 롤아웃 완료까지 block\nkubectl rollout history deploy/&lt;x&gt;      # revision 목록\nkubectl rollout undo deploy/&lt;x&gt;         # 직전 revision으로 롤백\nkubectl rollout undo deploy/&lt;x&gt; --to-revision=&lt;n&gt;   # 특정 revision\nkubectl rollout pause deploy/&lt;x&gt;        # 카나리 중 진행 정지\nkubectl rollout restart deploy/&lt;x&gt;      # 이미지 태그 그대로 재기동</code></pre>\n\n    <h3>실행 중인 artifact 특정 (digest / commit)</h3>\n    <pre class=\"snippet-card\"><code>git rev-parse --short HEAD                              # 현재 commit\nkubectl get pod &lt;pod&gt; -o jsonpath='{..imageID}'        # 실행 중 image digest\nkubectl get deploy &lt;x&gt; -o jsonpath='{..image}'         # 배포된 image 태그\nkubectl get cm &lt;name&gt; -o yaml                           # 적용된 config 내용</code></pre>\n    <div class=\"callout warn\"><span class=\"co-label\">주의</span><p>태그(<code>:latest</code>, <code>:v1.2</code>)는 재푸시되면 내용이 바뀔 수 있다. 무엇이 돌고 있는지 확정하려면 <b>image digest</b>(<code>@sha256:...</code>)를 봐라. digest 없이 \"롤백했다\"는 증거가 없다.</p></div>\n\n    <h3>배포 검증 (health / 버전)</h3>\n    <pre class=\"snippet-card\"><code>curl -f https://&lt;host&gt;/healthz          # 실패 시 non-zero exit (게이트용)\ncurl -fsS https://&lt;host&gt;/version         # 배포 버전이 기대값인지\ncurl -s -o /dev/null -w '%{http_code}\\n' https://&lt;host&gt;/   # 상태코드만</code></pre>\n\n    <h3>helm</h3>\n    <pre class=\"snippet-card\"><code>helm upgrade --install &lt;release&gt; &lt;chart&gt; -f values.yaml   # 없으면 설치, 있으면 갱신\nhelm diff upgrade &lt;release&gt; &lt;chart&gt; -f values.yaml        # 적용 전 diff (plugin)\nhelm history &lt;release&gt;                                    # revision 이력\nhelm rollback &lt;release&gt; &lt;revision&gt;                        # 특정 revision 복구</code></pre>\n    <div class=\"callout warn\"><span class=\"co-label\">주의</span><p>helm rollback / <code>kubectl rollout undo</code>는 <b>앱 코드만</b> 되돌린다. DB migration, message schema, 외부 side effect가 함께 나갔다면 롤백은 안전하지 않다 — <a href=\"#cheatdevops-ch4\">ch4</a>로.</p></div>\n\n    <table>\n      <tr><th>명령</th><th>용도</th><th>주의</th></tr>\n      <tr><td><code>kubectl exec -it &lt;pod&gt; -- sh</code></td><td>컨테이너 진입</td><td>운영 pod 상태 오염 주의</td></tr>\n      <tr><td><code>kubectl get rs</code></td><td>ReplicaSet(=revision)별 pod</td><td>구/신 버전 공존 확인</td></tr>\n      <tr><td><code>kubectl scale deploy/&lt;x&gt; --replicas=0</code></td><td>긴급 트래픽 차단</td><td>완전 중단 — drain 아님</td></tr>\n      <tr><td><code>kubectl diff -f &lt;file&gt;</code></td><td>apply 전 서버 상태와 diff</td><td>적용 전 반드시 확인</td></tr>\n      <tr><td><code>kubectl get pod &lt;pod&gt; -o yaml</code></td><td>전체 spec 덤프</td><td>secret env 노출 주의</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatdevops-ch2\">\n    <div class=\"ch-head\"><span class=\"ch-code\">DO-CS-02</span><h2>판단 한 줄</h2></div>\n    <table>\n      <tr><th>선택</th><th>언제 쓰나</th><th>주의</th></tr>\n      <tr><td>Rolling</td><td>자원 여유 없고 구/신 공존이 안전할 때 (기본값)</td><td>중간 상태에서 호환 깨지면 장애</td></tr>\n      <tr><td>Blue-green</td><td>즉시 전환·즉시 롤백이 중요하고 자원 2배 감당</td><td>DB·queue consumer는 단순 전환 불가</td></tr>\n      <tr><td>Canary</td><td>영향 반경을 작게 시작해 지표로 확대</td><td>중단 기준·관찰 창 없으면 그냥 \"조금 배포\"</td></tr>\n      <tr><td>Rollback</td><td>직전 버전이 확실히 정상이고 데이터 변경 없음</td><td>DB/schema 동반 시 roll-forward 검토</td></tr>\n      <tr><td>Roll-forward</td><td>롤백이 data loss·호환 깨짐을 유발할 때</td><td>수정 배포까지 시간 필요 — 그동안 완화책</td></tr>\n      <tr><td>Feature flag off</td><td>문제 기능만 즉시 끄고 배포는 유지</td><td>flag 없으면 불가 — redeploy가 유일</td></tr>\n      <tr><td>Redeploy</td><td>flag로 못 끄는 코드 경로 문제</td><td>롤아웃 시간 + 재검증 필요</td></tr>\n      <tr><td>Config 변경</td><td>동작만 바꾸면 되고 코드는 그대로</td><td>config drift·미기록 시 재현 불가</td></tr>\n      <tr><td>Code 변경</td><td>로직 자체를 고쳐야 할 때</td><td>새 artifact = 새 digest = 재검증</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatdevops-ch3\">\n    <div class=\"ch-head\"><span class=\"ch-code\">DO-CS-03</span><h2>자주 터지는 것 · 즉시 확인</h2></div>\n    <table>\n      <tr><th>신호</th><th>왜 위험</th><th>즉시 확인</th></tr>\n      <tr><td>어떤 artifact가 배포됐는지 모름 (digest 미확인)</td><td>무엇이 돌고 있는지 추적 불가 → 롤백 대상도 불명</td><td><code>kubectl get pod -o jsonpath='{..imageID}'</code>로 digest, commit SHA 연결</td></tr>\n      <tr><td>rollback을 실행만 하고 검증 안 함</td><td>\"되돌렸다\" 착각 — 태그 캐시/파드 미교체로 구 버전이 그대로</td><td><code>rollout status</code> + <code>curl /version</code> + digest 재확인</td></tr>\n      <tr><td>health check 없이 배포 성공 판정</td><td>파드 Running이어도 앱은 죽어있을 수 있음</td><td>readiness probe, <code>curl -f /healthz</code> exit code</td></tr>\n      <tr><td>config drift (수동 변경 누적)</td><td>선언 상태와 실제가 달라 재현·복구 깨짐</td><td><code>kubectl diff -f</code> / <code>helm diff</code>로 실제 vs 선언 비교</td></tr>\n      <tr><td>secret이 로그·image·env에 노출</td><td>폐기·재발급이 공급망 전체 이슈로 확대</td><td>CI 로그 masking, image layer, <code>get pod -o yaml</code> env 점검</td></tr>\n      <tr><td>DB migration이 배포와 함께 나감</td><td>롤백 시 데이터 shape 깨짐 — 단순 되돌리기 불가</td><td>expand/contract 여부, 구/신 앱 동시 동작 가능한지</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatdevops-ch4\">\n    <div class=\"ch-head\"><span class=\"ch-code\">DO-CS-04</span><h2>장애 증거 1카드</h2></div>\n    <div class=\"serial-card\"><span class=\"sc-label\">DEPLOYMENT FAILURE TRIAGE</span>재시도·롤백 누르기 전에 먼저 무엇이 돌고 있고, 무엇이 함께 바뀌었는지 증거를 고정한다.<br>1. 실행 중 image digest · config version 확인<br>2. health check / 상태코드 확인<br>3. error rate · latency 확인<br>4. 데이터 변경(DB migration·schema) 동반 여부 확인<br>5. rollback 후보 결정 — 단, 데이터 변경 동반이면 rollback 보류</div>\n    <table>\n      <tr><th>순서</th><th>질문</th><th>증거</th></tr>\n      <tr><td>1</td><td>지금 운영에 돌고 있는 image digest와 config version은?</td><td><code>kubectl get pod -o jsonpath='{..imageID}'</code>, cm/secret version, commit SHA</td></tr>\n      <tr><td>2</td><td>앱이 실제로 살아있나? health가 통과하나?</td><td><code>curl -f /healthz</code> exit code, readiness probe, <code>describe pod</code> 이벤트</td></tr>\n      <tr><td>3</td><td>사용자 영향은 어디에? error rate / latency 어디서 오르나?</td><td>dashboard, 상태코드 분포, 특정 route/tenant</td></tr>\n      <tr><td>4</td><td>이번 배포에 DB migration·schema·flag가 함께 나갔나?</td><td>migration log, <code>rollout history</code>, flag audit</td></tr>\n      <tr><td>5</td><td>rollback / pause / flag off 중 무엇을 먼저?</td><td>runbook, on-call 승인 기록</td></tr>\n    </table>\n    <div class=\"callout risk\"><span class=\"co-label\">복구·중단 기준</span><p>데이터 변경(DB migration·schema)이 동반된 배포는 <b>rollback 보류</b> — 구 버전이 새 schema를 못 읽으면 롤백이 2차 장애가 된다. 이 경우 roll-forward(수정 배포) 또는 <code>kubectl rollout pause</code>로 확산부터 멈추고 호환성을 확인한 뒤 결정한다.</p></div>\n  </section>\n\n<section id=\"doc-cheatlinux\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>Linux</h2></div>\n</section>\n\n<section id=\"cheatlinux-ch1\">\n    <div class=\"ch-head\"><span class=\"ch-code\">LX-CS-01</span><h2>핵심 명령·스니펫</h2></div>\n\n    <h3>프로세스</h3>\n    <pre class=\"snippet-card\"><code># 메모리 많이 먹는 순으로 상위 프로세스\nps aux --sort=-%mem | head\n\n# CPU 많이 먹는 순\nps aux --sort=-%cpu | head\n\n# 실시간 모니터 (htop 있으면 더 편함)\ntop\nhtop\n\n# 특정 프로세스 찾기\npgrep -a node\nps aux | grep '[n]ode'\n\n# 정상 종료 요청 (SIGTERM) → 안 죽으면 강제 종료\nkill -TERM &lt;pid&gt;\nkill -9 &lt;pid&gt;\n\n# 이름으로 종료\npkill -TERM -f 'my-service'</code></pre>\n\n    <h3>로그</h3>\n    <pre class=\"snippet-card\"><code># systemd 서비스 로그 실시간\njournalctl -u &lt;svc&gt; -f\n\n# 최근 시간 범위만\njournalctl -u &lt;svc&gt; --since '10 min ago'\njournalctl --since '2026-07-01 09:00' --until '2026-07-01 10:00'\n\n# 부팅 이후 / 이전 부팅\njournalctl -b\njournalctl -b -1\n\n# 파일 로그 실시간 추적 (rotation엔 -F)\ntail -f app.log\ntail -F app.log\n\n# 여러 로그에서 에러 재귀 검색\ngrep -rn 'err' /var/log\ngrep -rni 'error\\|panic\\|fatal' /var/log/myapp/</code></pre>\n\n    <h3>디스크</h3>\n    <pre class=\"snippet-card\"><code># 파일시스템 사용량\ndf -h\ndf -i          # inode 고갈은 별개로 확인\n\n# 현재 디렉터리에서 큰 것부터\ndu -sh * | sort -h\ndu -xhd1 /var | sort -h\n\n# 삭제됐지만 프로세스가 열고 있어 공간 점유 중인 파일\nlsof +L1</code></pre>\n\n    <div class=\"callout warn\"><span class=\"co-label\">주의</span><p><code>rm -rf</code>와 <code>kill -9</code>는 되돌릴 수 없다. 삭제 전 <code>pwd</code>와 대상 경로 확장 결과를 먼저 출력하고, 종료는 <code>kill -TERM</code>으로 시작한다. <code>kill -9</code>는 flush/cleanup을 건너뛴다.</p></div>\n\n    <h3>포트·소켓</h3>\n    <pre class=\"snippet-card\"><code># 특정 포트를 누가 쓰는지\nlsof -i :8080\n\n# LISTEN 중인 TCP 소켓과 프로세스\nss -tlnp\n\n# 모든 연결 상태\nss -tunap</code></pre>\n\n    <h3>서비스·검색</h3>\n    <table>\n      <tr><th>명령</th><th>용도</th><th>주의</th></tr>\n      <tr><td><code>systemctl status &lt;svc&gt;</code></td><td>서비스 상태·최근 로그·PID 확인</td><td>Active/exit code/restart 횟수 함께 본다</td></tr>\n      <tr><td><code>systemctl restart &lt;svc&gt;</code></td><td>서비스 재시작</td><td>재시작 전 영향 범위·rollback 확인</td></tr>\n      <tr><td><code>find / -name '*.log' -mtime -1</code></td><td>최근 1일 내 수정된 로그 찾기</td><td><code>/</code> 전체는 느림, 경로 좁히기</td></tr>\n      <tr><td><code>free -h</code></td><td>메모리·swap 사용량</td><td>available와 free는 다르다</td></tr>\n      <tr><td><code>uptime</code></td><td>load average 확인</td><td>코어 수 대비로 해석</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatlinux-ch2\">\n    <div class=\"ch-head\"><span class=\"ch-code\">LX-CS-02</span><h2>판단 한 줄</h2></div>\n    <table>\n      <tr><th>선택</th><th>언제 쓰나</th><th>주의</th></tr>\n      <tr><td><code>SIGTERM</code> (<code>kill -15</code>)</td><td>기본. 프로세스에 정리할 시간을 줌</td><td>graceful shutdown 로그를 먼저 확인</td></tr>\n      <tr><td><code>SIGKILL</code> (<code>kill -9</code>)</td><td>SIGTERM 실패 시 마지막 수단</td><td>cleanup hook·flush 없이 즉사, 상태 손상 가능</td></tr>\n      <tr><td>hard link</td><td>같은 inode에 이름 여러 개, 원본 지워도 데이터 유지</td><td>파일시스템 경계·디렉터리 불가</td></tr>\n      <tr><td>soft link (<code>ln -s</code>)</td><td>경로를 가리키는 참조, 파일시스템 넘나듦</td><td>원본 지우면 dangling link</td></tr>\n      <tr><td><code>&gt;</code></td><td>파일 새로 덮어쓰기</td><td>기존 내용 즉시 날아감</td></tr>\n      <tr><td><code>&gt;&gt;</code></td><td>파일 끝에 이어붙이기</td><td>로그 누적엔 이쪽</td></tr>\n      <tr><td>systemd</td><td>상시 데몬, 의존성·재시작·로그 관리 필요할 때</td><td>unit 파일과 journal에 통합</td></tr>\n      <tr><td>cron</td><td>정해진 시각에 주기 실행</td><td>환경변수·PATH가 셸과 다름</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatlinux-ch3\">\n    <div class=\"ch-head\"><span class=\"ch-code\">LX-CS-03</span><h2>자주 터지는 것 · 즉시 확인</h2></div>\n    <table>\n      <tr><th>신호</th><th>왜 위험</th><th>즉시 확인</th></tr>\n      <tr><td>디스크 100%인데 <code>df</code>상 용량이 남아 보임</td><td>삭제됐지만 프로세스가 연 파일이 공간을 점유</td><td><code>lsof +L1</code> → 해당 프로세스 restart</td></tr>\n      <tr><td>좀비(defunct)·고아 프로세스 누적</td><td>부모가 <code>wait()</code>로 회수(reaping)하지 않음. 컨테이너에선 <b>PID 1</b>이 init로서 reaping 책임</td><td><code>ps aux | grep defunct</code>, 컨테이너면 init(예: tini) 여부</td></tr>\n      <tr><td>프로세스가 갑자기 죽고 로그에 흔적 없음</td><td>OOM killer가 메모리 부족으로 강제 종료</td><td><code>dmesg | grep -i 'oom\\|killed'</code>, <code>journalctl -k</code></td></tr>\n      <tr><td><code>chmod 777</code> 남용</td><td>누구나 쓰기·실행 가능, 권한 문제를 덮기만 함</td><td><code>id</code>, <code>stat</code>, <code>namei -l &lt;path&gt;</code>로 실제 원인</td></tr>\n      <tr><td>로그 로테이션 부재</td><td>단일 로그 파일이 디스크를 서서히 채움</td><td><code>ls -lh</code>로 크기, <code>logrotate</code> 설정 확인</td></tr>\n      <tr><td>보는 로그 파일과 앱이 쓰는 파일이 다름</td><td>rotation으로 inode가 바뀜</td><td><code>tail -F</code>, <code>journalctl --since</code></td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatlinux-ch4\">\n    <div class=\"ch-head\"><span class=\"ch-code\">LX-CS-04</span><h2>장애 증거 1카드</h2></div>\n    <div class=\"serial-card\"><span class=\"sc-label\">DISK FULL TRIAGE</span>1. <code>df -h</code> · <code>df -i</code>로 block/inode 중 무엇이 찼는지 구분<br>2. <code>du -xhd1 /path | sort -h</code>로 큰 디렉터리 추적<br>3. <code>lsof +L1</code>로 삭제됐지만 열린 파일 확인 (핵심 함정)<br>4. 로그·코어덤프(<code>/var/log</code>, <code>core.*</code>) 크기 확인<br>5. 백업·owner·서비스 영향 확인 후 안전 삭제</div>\n    <table>\n      <tr><th>순서</th><th>질문</th><th>증거</th></tr>\n      <tr><td>1</td><td>block이 찼나 inode가 찼나?</td><td><code>df -h</code>, <code>df -i</code>의 Use%</td></tr>\n      <tr><td>2</td><td>어느 디렉터리가 큰가?</td><td><code>du -xhd1 /path | sort -h</code></td></tr>\n      <tr><td>3</td><td>지웠는데 공간이 안 돌아오나?</td><td><code>lsof +L1</code>의 열린 삭제 파일</td></tr>\n      <tr><td>4</td><td>로그·덤프가 원인인가?</td><td>큰 <code>.log</code>, <code>core.*</code> 파일</td></tr>\n    </table>\n    <div class=\"callout warn\"><span class=\"co-label\">복구·중단</span><p>3번에서 열린 삭제 파일이 잡히면 파일을 더 지우지 말고 해당 프로세스를 restart해 fd를 놓게 한다. 대상 경로를 눈으로 확인하지 못하면 삭제를 중단한다.</p></div>\n  </section>\n\n<section id=\"doc-cheatdocker\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>Docker</h2></div>\n</section>\n\n<section id=\"cheatdocker-ch1\">\n    <div class=\"ch-head\"><span class=\"ch-code\">DK-CS-01</span><h2>핵심 명령·스니펫</h2></div>\n\n    <h3>컨테이너 상태 · 로그</h3>\n    <pre class=\"snippet-card\"><code>docker ps                    # 실행 중인 컨테이너\ndocker ps -a                 # 종료된 것 포함 전체 + EXIT CODE\ndocker ps --format 'table {{.Names}}\\t{{.Status}}\\t{{.Ports}}'\ndocker logs -f &lt;c&gt;            # 로그 실시간 추적 (가장 자주 씀)\ndocker logs --tail 100 &lt;c&gt;   # 마지막 100줄만\ndocker logs --since 10m &lt;c&gt;   # 최근 10분치만\ndocker stats                 # CPU/MEM/NET 실시간 (Ctrl+C로 종료)\ndocker stats --no-stream     # 한 번만 찍고 종료</code></pre>\n\n    <h3>내부 진입 · 검사</h3>\n    <pre class=\"snippet-card\"><code>docker exec -it &lt;c&gt; sh       # 컨테이너 내부 shell (alpine)\ndocker exec -it &lt;c&gt; bash     # bash 있는 이미지\ndocker exec &lt;c&gt; env          # 주입된 env 덤프\ndocker inspect &lt;c&gt;           # 전체 설정(mount/env/network) JSON\ndocker inspect --format '{{.State.ExitCode}}' &lt;c&gt;\ndocker inspect --format '{{json .Mounts}}' &lt;c&gt;\ndocker inspect --format '{{.Id}}' &lt;img&gt;   # 이미지 digest 고정 확인\ndocker port &lt;c&gt;              # 포트 매핑 확인</code></pre>\n\n    <h3>이미지 · 빌드</h3>\n    <pre class=\"snippet-card\"><code>docker build -t app:tag .            # 태그 박아서 빌드 (latest 금지)\ndocker build --no-cache -t app:tag . # 캐시 무시하고 처음부터\ndocker build --target builder -t x . # multi-stage 특정 stage만\ndocker history app:tag               # layer별 크기 · 명령 추적\ndocker images                        # 로컬 이미지 목록\ndocker run --rm -it --entrypoint sh app:tag  # 시작 못하는 이미지 진입</code></pre>\n\n    <h3>Compose</h3>\n    <pre class=\"snippet-card\"><code>docker compose up -d          # 백그라운드로 전체 기동\ndocker compose up -d --build   # 이미지 재빌드 후 기동\ndocker compose logs -f         # 전체 서비스 로그 추적\ndocker compose logs -f &lt;svc&gt;   # 특정 서비스만\ndocker compose ps              # 서비스 상태\ndocker compose config          # .env 병합된 최종 설정 확인\ndocker compose down            # 컨테이너+네트워크 정리\ndocker compose down -v         # 볼륨까지 삭제 (데이터 날아감)\ndocker compose exec &lt;svc&gt; sh    # 서비스 내부 진입</code></pre>\n\n    <table>\n      <tr><th>명령</th><th>용도</th><th>주의</th></tr>\n      <tr><td><code>docker ps -a</code></td><td>종료 컨테이너 EXIT CODE 확인</td><td>STATUS 컬럼이 원인 첫 단서</td></tr>\n      <tr><td><code>docker logs -f &lt;c&gt;</code></td><td>앱 로그 실시간</td><td>앱이 stdout/stderr로 찍어야 보임</td></tr>\n      <tr><td><code>docker exec -it &lt;c&gt; sh</code></td><td>실행 중 컨테이너 진입</td><td>distroless엔 shell 없음</td></tr>\n      <tr><td><code>docker cp &lt;c&gt;:/path ./</code></td><td>컨테이너 파일 밖으로 복사</td><td>디버깅용, 영속 수단 아님</td></tr>\n      <tr><td><code>docker rm -f &lt;c&gt;</code></td><td>강제 삭제</td><td>volume 안 붙었으면 데이터 소실</td></tr>\n    </table>\n\n    <div class=\"callout warn\"><span class=\"co-label\">주의</span><p><code>docker system prune -af</code> 는 중지된 컨테이너·미사용 이미지·네트워크·<b>빌드 캐시</b>를 전부 지웁니다. <code>--volumes</code> 를 붙이면 <b>미사용 named volume(=DB 데이터)까지 삭제</b>됩니다. 운영 근처에서 함부로 실행 금지.</p></div>\n  </section>\n\n  <section id=\"cheatdocker-ch2\">\n    <div class=\"ch-head\"><span class=\"ch-code\">DK-CS-02</span><h2>판단 한 줄</h2></div>\n    <table>\n      <tr><th>선택</th><th>언제 쓰나</th><th>주의</th></tr>\n      <tr><td>bind mount</td><td>로컬 개발, 소스 변경 즉시 반영</td><td>host 권한·성능 영향, 운영엔 부적합</td></tr>\n      <tr><td>named volume</td><td>DB·업로드 등 컨테이너 교체 뒤에도 보존</td><td>삭제 전 소유자·백업 확인, <code>down -v</code> 조심</td></tr>\n      <tr><td>CMD</td><td>기본 실행 인자, 오버라이드 가능하게</td><td><code>docker run</code> 뒤 인자로 통째 교체됨</td></tr>\n      <tr><td>ENTRYPOINT</td><td>컨테이너를 실행파일처럼 고정</td><td>인자 교체엔 <code>--entrypoint</code> 필요</td></tr>\n      <tr><td>multi-stage build</td><td>빌드 도구와 런타임 산출물 분리</td><td>빌드 stage의 secret/cache가 최종에 안 남게</td></tr>\n      <tr><td>alpine</td><td>작고 shell 있음, 일반 서비스</td><td>musl libc 호환·DNS 이슈 간혹</td></tr>\n      <tr><td>distroless</td><td>최소 공격면, 운영 배포</td><td>shell·패키지매니저 없음, 디버깅 불편</td></tr>\n      <tr><td>restart policy</td><td><code>unless-stopped</code>=재부팅 후 자동, <code>on-failure</code>=비정상만</td><td><code>always</code>는 수동 중지도 되살림</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatdocker-ch3\">\n    <div class=\"ch-head\"><span class=\"ch-code\">DK-CS-03</span><h2>자주 터지는 것 · 즉시 확인</h2></div>\n    <table>\n      <tr><th>신호</th><th>왜 위험</th><th>즉시 확인</th></tr>\n      <tr><td><code>latest</code> 태그로 배포</td><td>rollback·감사 불가, 재배포 때 다른 이미지</td><td>immutable tag, <code>docker inspect --format '{{.Id}}'</code> digest 고정</td></tr>\n      <tr><td>layer 캐시 무효화</td><td><code>COPY . .</code>를 앞에 두면 소스 한 줄 바뀔 때마다 의존성 재설치</td><td>의존성 파일 먼저 <code>COPY</code>·install, 소스는 뒤</td></tr>\n      <tr><td>컨테이너 내부에 상태 저장</td><td>재생성 시 layer 휘발, 데이터 유실</td><td>volume/bind mount 붙었는지 <code>inspect .Mounts</code></td></tr>\n      <tr><td>이미지 과대</td><td>배포·scan 느리고 CVE 많음</td><td><code>docker history</code>로 큰 layer, multi-stage·<code>.dockerignore</code></td></tr>\n      <tr><td>healthcheck 부재</td><td>준비 안 된 앱에 traffic 유입</td><td><code>HEALTHCHECK</code>, readiness endpoint, dependency 상태</td></tr>\n      <tr><td>Compose에서 <code>localhost</code>로 타 서비스 호출</td><td>컨테이너 간 통신 실패</td><td>service name을 DNS로 사용</td></tr>\n      <tr><td><code>prune</code>로 볼륨 삭제</td><td>DB 데이터 영구 소실</td><td><code>--volumes</code> 플래그 여부, 실행 전 <code>volume ls</code></td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatdocker-ch4\">\n    <div class=\"ch-head\"><span class=\"ch-code\">DK-CS-04</span><h2>장애 증거 1카드</h2></div>\n    <div class=\"serial-card\"><span class=\"sc-label\">CONTAINER WON'T START</span>1. <code>docker ps -a</code> → STATUS/EXIT CODE 확인 (0=정상종료, 137=OOM/kill, 1=앱오류)<br>2. <code>docker logs --tail 100 &lt;c&gt;</code> → 첫 에러 로그<br>3. <code>docker inspect &lt;c&gt;</code> → mount / env / entrypoint 확인<br>4. <code>docker inspect --format '{{json .State.Health}}' &lt;c&gt;</code> → 헬스체크 실패 여부<br>5. <code>docker inspect --format '{{.Id}}' &lt;img&gt;</code> → 실행 이미지 digest가 의도한 것인지<br>6. <code>docker run --rm -it --entrypoint sh &lt;img&gt;</code> → 이미지 자체 진입해 파일·bind 검증</div>\n    <table>\n      <tr><th>순서</th><th>질문</th><th>증거</th></tr>\n      <tr><td>1</td><td>어떻게 죽었나</td><td><code>ps -a</code> EXIT CODE + STATUS</td></tr>\n      <tr><td>2</td><td>앱이 뭘 남겼나</td><td><code>logs</code> 첫 에러 라인</td></tr>\n      <tr><td>3</td><td>설정이 맞나</td><td><code>inspect</code> env·mount·entrypoint</td></tr>\n      <tr><td>4</td><td>준비됐다고 보고했나</td><td>healthcheck State.Health</td></tr>\n      <tr><td>5</td><td>맞는 이미지인가</td><td>image digest(<code>.Id</code>)</td></tr>\n    </table>\n    <div class=\"callout warn\"><span class=\"co-label\">복구/중단</span><p>EXIT 137이면 메모리 한계(<code>--memory</code>)나 외부 OOM kill부터 본다. logs·inspect로 원인을 짚기 전엔 재빌드 반복 금지 — 이미지가 아니라 env·mount·network 설정 문제인 경우가 많다.</p></div>\n  </section>\n\n<section id=\"doc-cheatinterview\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>Interview</h2></div>\n</section>\n\n<section id=\"cheatinterview-ch1\">\n    <div class=\"ch-head\"><span class=\"ch-code\">IV-CS-01</span><h2>즉답 구조 템플릿</h2></div>\n    <p class=\"lede\">질문을 받으면 키워드부터 쏟지 말고 아래 구조를 머릿속에 세운다. 결론 먼저, 근거는 조건과 함께.</p>\n\n    <div class=\"serial-card\"><span class=\"sc-label\">30초 답변 — 정의 · 차이 · 가벼운 확인</span>\n      1. 결론 한 문장: \"핵심은 X입니다.\"<br>\n      2. 근거 한 문장: \"왜냐하면 Y이기 때문입니다.\"<br>\n      3. 경계 한 문장: \"다만 Z 조건에서는 달라집니다.\"<br>\n      <b>예)</b> \"REST와 GraphQL의 핵심 차이는 데이터를 서버가 정하느냐 클라이언트가 정하느냐입니다. 그래서 화면마다 필요한 필드가 크게 다르면 GraphQL이 유리합니다. 다만 캐싱과 러닝커브 비용은 감수해야 합니다.\"\n    </div>\n\n    <div class=\"serial-card\"><span class=\"sc-label\">90초 답변 — 개념 · 기준 · trade-off · 예시</span>\n      1. 개념 정의 + 왜 필요한가<br>\n      2. 선택 기준 2~3개 (트래픽, 일관성, 운영 비용 등)<br>\n      3. trade-off: 무엇을 얻고 무엇을 포기하나<br>\n      4. 실무 예시 한 줄 (직접/개념 경계 명시)<br>\n      <b>예)</b> \"Redis 캐시는 반복 조회 비용을 줄이려고 씁니다. 판단 기준은 읽기 빈도, 데이터 신선도 요구, 캐시 무효화 비용입니다. 속도는 얻지만 정합성 경계를 직접 관리해야 하는 게 비용입니다. 제가 맡았던 조회 API에서는 TTL과 write-through로 처리했습니다.\"\n    </div>\n\n    <div class=\"serial-card\"><span class=\"sc-label\">STAR — 행동 질문 (협업 · 갈등 · 실패 · 리더십)</span>\n      <b>S</b>ituation: 언제, 어떤 맥락에서 (한 문장)<br>\n      <b>T</b>ask: 내가 맡은 과제와 제약<br>\n      <b>A</b>ction: 내가 한 결정과 행동 (여기가 핵심, 가장 길게)<br>\n      <b>R</b>esult: 결과 지표 + 배운 점 / 바꾼 행동<br>\n      <b>예)</b> \"배포 후 장애가 반복됐고(S), 저는 원인 파악과 재발 방지를 맡았습니다(T). 로그를 추적해 특정 쿼리 타임아웃을 찾고, 배포 전 부하 체크를 파이프라인에 넣었습니다(A). 이후 같은 유형 장애가 사라졌고, 배포 전 검증 습관이 팀에 남았습니다(R).\"\n    </div>\n\n    <div class=\"serial-card\"><span class=\"sc-label\">Trade-off 답변 프레임</span>\n      \"<b>A</b>는 X 때문에 좋고, <b>B</b>는 Y 때문에 좋습니다. 그래서 <b>우리 상황</b>에선 Z 기준이 더 중요하니 [선택]입니다.\"<br>\n      <b>예)</b> \"MSA는 팀 독립 배포 때문에 좋고, 모놀리식은 운영 단순함 때문에 좋습니다. 그래서 팀이 작고 도메인 경계가 아직 흐린 지금은 배포 속도보다 단순함이 중요해서 모놀리식으로 시작하겠습니다.\"\n    </div>\n\n    <table>\n      <tr><th>프레임</th><th>구조</th><th>언제</th></tr>\n      <tr><td>30초</td><td>결론 · 근거 · 경계</td><td>정의, 차이, 가벼운 확인</td></tr>\n      <tr><td>90초</td><td>개념 · 기준 · trade-off · 예시</td><td>기술 이해도 + 실무 감각</td></tr>\n      <tr><td>3분</td><td>문제 · 대안 · 실패 모드 · 검증</td><td>프로젝트 · 설계 · 장애</td></tr>\n      <tr><td>STAR</td><td>Situation · Task · Action · Result</td><td>협업 · 갈등 · 실패 · 리더십</td></tr>\n      <tr><td>Trade-off</td><td>A는 X, B는 Y, 우리는 Z</td><td>Redis · MSA · JWT · SSR · NoSQL 선택</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatinterview-ch2\">\n    <div class=\"ch-head\"><span class=\"ch-code\">IV-CS-02</span><h2>질문 유형별 접근</h2></div>\n    <p class=\"lede\">질문 유형을 먼저 분류하면 무엇을 첫 문장으로 말할지 정해진다.</p>\n    <table>\n      <tr><th>질문 유형</th><th>먼저 말할 것</th><th>예시 시작 문장</th></tr>\n      <tr><td>경험형</td><td>문제와 내 역할부터. 스택 나열 금지.</td><td>\"제가 맡은 문제는 ~였고, 제 역할은 ~였습니다.\"</td></tr>\n      <tr><td>설계형</td><td>요구사항·제약을 먼저 되묻고 좁힌다.</td><td>\"트래픽 규모와 일관성 요구를 먼저 확인하고 싶습니다.\"</td></tr>\n      <tr><td>트레이드오프형</td><td>양쪽 장점 → 우리 상황 기준 → 선택.</td><td>\"A는 ~ 때문에, B는 ~ 때문에 좋습니다. 우리 상황에선 ~\"</td></tr>\n      <tr><td>디버깅형</td><td>증상 → 가설 → 좁히는 순서. 재현부터.</td><td>\"먼저 재현하고, 범위를 로그로 좁히겠습니다.\"</td></tr>\n      <tr><td>모르는 질문</td><td>아는 경계 명시 → 원리 추론 → 확인 방법.</td><td>\"직접 경험은 없지만 원리로 추론하면 ~\"</td></tr>\n      <tr><td>압박 질문</td><td>방어 대신 전제·기준·증거로 재구성.</td><td>\"그 지적의 전제를 먼저 정리하면 ~\"</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatinterview-ch3\">\n    <div class=\"ch-head\"><span class=\"ch-code\">IV-CS-03</span><h2>감점 신호 · 즉시 확인</h2></div>\n    <p class=\"lede\">전문성은 말의 양이 아니라 경계·기준·증거에서 드러난다. 아래는 면접관이 즉시 감점하는 신호.</p>\n    <table>\n      <tr><th>감점 신호</th><th>왜 위험한가</th><th>즉시 확인 / 보정</th></tr>\n      <tr><td>결론 없이 장황</td><td>판단 구조가 안 보이고 시간만 쓴다.</td><td>첫 문장을 결론으로. \"핵심은 X입니다\"로 시작.</td></tr>\n      <tr><td>직접 경험과 이론을 같은 톤으로</td><td>꼬리질문에서 신뢰가 무너진다.</td><td>\"직접 해본 부분\"과 \"설계한다면\"을 분리해 말함.</td></tr>\n      <tr><td>기술명만 나열</td><td>키워드는 있고 적용 판단이 없다.</td><td>정의 → 선택 기준 → trade-off로 재구성.</td></tr>\n      <tr><td>trade-off 없이 정답 단정</td><td>\"항상/무조건\"은 조건을 무시한 답.</td><td>규모·latency·consistency·비용 조건을 붙임.</td></tr>\n      <tr><td>모른다는 걸 숨김</td><td>추측을 사실처럼 말하면 바로 들킨다.</td><td>모르는 범위 인정 + 확인 방법 제시로 닫음.</td></tr>\n      <tr><td>성과가 팀 단위 표현뿐</td><td>본인 기여와 의사결정이 흐려진다.</td><td>내 역할·내가 바꾼 선택·결과 지표를 분리.</td></tr>\n      <tr><td>실패에 재발 방지가 없음</td><td>학습 능력 대신 변명으로 들린다.</td><td>관측·테스트·리뷰 기준을 어떻게 바꿨는지 말함.</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheatinterview-ch4\">\n    <div class=\"ch-head\"><span class=\"ch-code\">IV-CS-04</span><h2>모르는 질문 1카드</h2></div>\n    <div class=\"serial-card\"><span class=\"sc-label\">STUCK ANSWER TRIAGE</span>\n      모르는 질문에서 조급하게 키워드를 쏟지 않는다. 아래 순서로 회복한다.<br>\n      1. 질문 재정의 — \"운영 기준인지, 개념 비교 기준인지 먼저 나누겠습니다.\"<br>\n      2. 아는 경계 명시 — \"직접 운영 경험은 없지만, 원리는 이렇게 이해합니다.\"<br>\n      3. 원리로 추론 — \"일관성·latency·복구 비용 중 무엇이 중요하냐에 따라 갈립니다.\"<br>\n      4. 검증 방법 제안 — \"그래서 작은 부하 테스트와 rollback 리허설로 확인하겠습니다.\"<br>\n      5. 솔직히 모른다 + 학습 계획 — \"이 부분은 확실치 않아 끝나고 문서로 확인하겠습니다.\"\n    </div>\n    <table>\n      <tr><th>순서</th><th>질문</th><th>말할 증거 / 예시</th></tr>\n      <tr><td>1</td><td>이 질문이 진짜 묻는 건 뭔가?</td><td>\"운영 트래픽 기준인지 개념 비교인지 나누겠습니다.\"</td></tr>\n      <tr><td>2</td><td>내가 확실히 아는 경계는?</td><td>\"직접 해본 건 API 계약과 장애 재현입니다.\"</td></tr>\n      <tr><td>3</td><td>원리로 어디까지 추론되나?</td><td>\"CAP상 일관성을 택하면 가용성을 일부 포기합니다.\"</td></tr>\n      <tr><td>4</td><td>어떻게 검증할 수 있나?</td><td>\"작은 부하 테스트로 병목 지점부터 확인합니다.\"</td></tr>\n      <tr><td>5</td><td>모르는 건 어떻게 닫나?</td><td>\"확실치 않으니 확인 후 정확히 답 드리겠습니다.\"</td></tr>\n    </table>\n    <div class=\"callout warn\"><span class=\"co-label\">중단 기준</span><p>추측을 사실처럼 이어 붙이는 순간 멈춘다. 모르면 \"여기까지는 알고, 그다음은 확인이 필요합니다\"로 경계를 긋는 게 지어내는 답보다 항상 낫다.</p></div>\n  </section>\n\n<section id=\"doc-cheattools\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>Tools·Shortcuts·Commands</h2></div>\n</section>\n\n<section id=\"cheattools-ch1\">\n    <div class=\"ch-head\"><span class=\"ch-code\">TL-CS-01</span><h2>핵심 명령·스니펫</h2></div>\n\n    <h3>Git — 상태 · 이력 보기</h3>\n    <pre class=\"snippet-card\"><code># 변경 파일 짧게 (가장 많이 씀)\ngit status --short\n\n# 그래프로 전체 브랜치 흐름\ngit log --oneline --graph --all\n\n# 특정 파일 변경 이력 (이름 변경 추적 포함)\ngit log --follow -- path/to/file\n\n# 스테이지된 것 vs 작업 중인 것 분리 확인\ngit diff            # 아직 add 안 한 변경\ngit diff --staged   # add 한 변경</code></pre>\n\n    <h3>Git — 히스토리 고치기</h3>\n    <pre class=\"snippet-card\"><code># 최근 3개 커밋 정리 (squash/reword/drop)\ngit rebase -i HEAD~3\n\n# 방금 커밋 취소하되 변경은 스테이지에 남김\ngit reset --soft HEAD~1\n\n# 마지막 커밋 메시지/내용 수정\ngit commit --amend\n\n# 다른 브랜치의 특정 커밋만 가져오기\ngit cherry-pick &lt;sha&gt;</code></pre>\n\n    <h3>Git — 잠깐 치워두기 · 복구</h3>\n    <pre class=\"snippet-card\"><code># 작업 중인 변경 임시 저장 → 되돌리기\ngit stash\ngit stash pop\n\n# 유실 복구의 핵심 — 모든 HEAD 이동 기록\ngit reflog\ngit reset --hard HEAD@{2}   # reflog에서 찾은 지점으로 복구</code></pre>\n\n    <h3>Git — 버그 커밋 이분 탐색 (bisect)</h3>\n    <pre class=\"snippet-card\"><code># 언제 깨졌는지 자동 이분 탐색\ngit bisect start\ngit bisect bad              # 현재(깨진) 상태\ngit bisect good &lt;sha&gt;       # 정상이던 과거 커밋\n# git이 중간 커밋 체크아웃 → 테스트 후 good/bad 반복\ngit bisect reset           # 끝나면 원위치</code></pre>\n\n    <h3>Terminal — 검색 · 파싱 · 파이프</h3>\n    <pre class=\"snippet-card\"><code># 재귀 검색 + 줄번호 (파일명·API path 추적)\ngrep -rn 'keyword' src/\n\n# JSON 필드 뽑기\ncurl -s api.example.com/orders | jq '.data[] | {id, status}'\n\n# 검색 결과를 다음 명령으로 넘기기\ngrep -rl 'TODO' src/ | xargs wc -l\n\n# 예전에 친 명령 다시 찾기\nhistory | grep rebase</code></pre>\n\n    <h3>HTTP — API 찌르기</h3>\n    <pre class=\"snippet-card\"><code># 헤더까지 보기 — status·응답 헤더 확인 (첫 진단)\ncurl -i https://api.example.com/health\n\n# POST + JSON\ncurl -X POST -H 'Content-Type: application/json' \\\n  -d '{\"amount\":1000}' https://api.example.com/payments\n\n# 연결 전 구간 프로파일 (2&gt;&amp;1로 stderr 합치기)\ncurl -v https://api.example.com/orders 2&gt;&amp;1 | head -20</code></pre>\n\n    <h3>Node · 패키지</h3>\n    <pre class=\"snippet-card\"><code># 설치 없이 일회성 실행\npnpm dlx create-next-app my-app\nnpx tsc --noEmit\n\n# 프로젝트가 제공하는 스크립트 목록 확인\nnpm run</code></pre>\n\n    <table>\n      <tr><th>명령</th><th>용도</th><th>주의</th></tr>\n      <tr><td><code>git status --short</code></td><td>변경 파일 빠른 확인, 첫 진단</td><td>습관화 1순위</td></tr>\n      <tr><td><code>git reset --soft HEAD~1</code></td><td>커밋만 취소, 변경 보존</td><td><code>--hard</code>와 혼동 금지</td></tr>\n      <tr><td><code>git reflog</code></td><td>유실 커밋·브랜치 복구 진입점</td><td>대부분의 \"날아갔다\"는 여기서 복구</td></tr>\n      <tr><td><code>git stash</code> / <code>pop</code></td><td>브랜치 안 만들고 잠깐 치우기</td><td>여러 개 쌓이면 <code>stash list</code></td></tr>\n      <tr><td><code>grep -rn</code></td><td>재귀 검색 + 줄번호</td><td>큰 저장소는 <code>rg</code>가 빠름</td></tr>\n      <tr><td><code>curl -i &lt;url&gt;</code></td><td>status·헤더 확인</td><td><code>-s</code>로 progress 끄기</td></tr>\n      <tr><td><code>pnpm dlx</code> / <code>npx</code></td><td>전역 설치 없이 CLI 실행</td><td>버전 고정 필요하면 명시</td></tr>\n    </table>\n    <div class=\"callout warn\"><span class=\"co-label\">주의</span><p><code>git reset --hard</code>는 작업 중 변경을 <b>복구 없이</b> 날린다. 실행 전 <code>git stash</code>나 커밋으로 대피시켜라. rebase로 이미 push한 커밋을 고친 뒤 <code>git push --force</code>하면 팀의 히스토리가 깨진다 — 공유 브랜치엔 <code>--force-with-lease</code>를 쓰고, main엔 아예 하지 마라.</p></div>\n  </section>\n\n  <section id=\"cheattools-ch2\">\n    <div class=\"ch-head\"><span class=\"ch-code\">TL-CS-02</span><h2>판단 한 줄</h2></div>\n    <table>\n      <tr><th>선택</th><th>언제 쓰나</th><th>주의</th></tr>\n      <tr><td>rebase</td><td>내 로컬 브랜치 히스토리를 선형으로 정리할 때</td><td>이미 push·공유된 커밋엔 금지 (히스토리 재작성)</td></tr>\n      <tr><td>merge</td><td>공유 브랜치 통합, 실제 병합 시점을 남기고 싶을 때</td><td>graph가 복잡해짐, 하지만 안전</td></tr>\n      <tr><td><code>reset --soft</code></td><td>커밋만 취소, 변경은 스테이지에 그대로</td><td>커밋 다시 묶을 때</td></tr>\n      <tr><td><code>reset --mixed</code></td><td>커밋·스테이지 취소, 작업 변경은 보존 (기본값)</td><td>add부터 다시</td></tr>\n      <tr><td><code>reset --hard</code></td><td>커밋·스테이지·작업 변경 전부 폐기</td><td>복구 어려움 — reflog 외엔 없음</td></tr>\n      <tr><td>stash</td><td>잠깐(분~시간) 치웠다 곧 되돌릴 때</td><td>오래 두면 잊음 → 브랜치가 나음</td></tr>\n      <tr><td>branch</td><td>수명이 길거나 남과 공유할 작업일 때</td><td>이름으로 맥락이 남음</td></tr>\n      <tr><td>npm</td><td>표준·호환성 우선, CI 단순함</td><td>디스크·설치속도 불리</td></tr>\n      <tr><td>pnpm</td><td>모노레포·디스크 절약·빠른 설치</td><td>lockfile·hoisting 동작 팀과 합의</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheattools-ch3\">\n    <div class=\"ch-head\"><span class=\"ch-code\">TL-CS-03</span><h2>자주 터지는 것 · 즉시 확인</h2></div>\n    <table>\n      <tr><th>신호</th><th>왜 위험</th><th>즉시 확인</th></tr>\n      <tr><td><code>git reset --hard</code>로 작업이 사라짐</td><td>스테이지·작업 변경이 되돌릴 수 없이 폐기됨</td><td><b><code>git reflog</code></b>로 직전 HEAD 찾아 <code>reset --hard HEAD@{n}</code></td></tr>\n      <tr><td>rebase 후 <code>push --force</code>로 팀 히스토리가 깨짐</td><td>남이 받은 커밋이 사라져 pull 충돌·유실</td><td>공유 브랜치는 <code>--force-with-lease</code>, main은 금지. 이미 깼으면 동료 reflog로 복원</td></tr>\n      <tr><td>.gitignore 누락으로 secret이 커밋됨</td><td>토큰 유출 — 히스토리에 남아 삭제해도 추적됨</td><td>즉시 <b>토큰 재발급</b>, history 정리(filter-repo), .gitignore 추가</td></tr>\n      <tr><td>detached HEAD 상태에서 커밋함</td><td>브랜치에 안 붙은 커밋 → 체크아웃 옮기면 유실</td><td><code>git switch -c fix-branch</code>로 지금 커밋을 브랜치로 고정</td></tr>\n      <tr><td>내 로컬만 빌드/실행 실패</td><td>런타임·env·lockfile 차이로 재현 안 됨</td><td>버전 확인 → clean install → 팀/CI와 diff (ch4 triage)</td></tr>\n    </table>\n  </section>\n\n  <section id=\"cheattools-ch4\">\n    <div class=\"ch-head\"><span class=\"ch-code\">TL-CS-04</span><h2>장애 증거 1카드</h2></div>\n\n    <h3>IDE·브라우저 단축키 (mac / win)</h3>\n    <table>\n      <tr><th>목적</th><th>macOS</th><th>Windows/Linux</th><th>도구·용도</th></tr>\n      <tr><td>파일 빠른 열기</td><td><code>Cmd+P</code></td><td><code>Ctrl+P</code></td><td>VS Code — 파일명 일부로 이동</td></tr>\n      <tr><td>명령 팔레트</td><td><code>Cmd+Shift+P</code></td><td><code>Ctrl+Shift+P</code></td><td>VS Code — 모든 command 실행</td></tr>\n      <tr><td>전체 검색</td><td><code>Cmd+Shift+F</code></td><td><code>Ctrl+Shift+F</code></td><td>VS Code — 문자열·API path 추적</td></tr>\n      <tr><td>심볼 이동</td><td><code>Cmd+Shift+O</code></td><td><code>Ctrl+Shift+O</code></td><td>VS Code — 큰 파일 내 함수 점프</td></tr>\n      <tr><td>정의로 이동</td><td><code>F12</code></td><td><code>F12</code></td><td>VS Code — 타입·함수 정의</td></tr>\n      <tr><td>멀티 커서</td><td><code>Cmd+D</code> / <code>Option+Click</code></td><td><code>Ctrl+D</code> / <code>Alt+Click</code></td><td>VS Code — 같은 토큰 반복 수정</td></tr>\n      <tr><td>DevTools 열기</td><td><code>Cmd+Option+I</code></td><td><code>Ctrl+Shift+I</code></td><td>브라우저 — Network·Console</td></tr>\n      <tr><td>요청 다시 보내기</td><td><code>Cmd+Enter</code></td><td><code>Ctrl+Enter</code></td><td>Postman — 저장한 API 재현</td></tr>\n    </table>\n\n    <div class=\"serial-card\"><span class=\"sc-label\">TOOLING INCIDENT TRIAGE</span>\n      \"내 로컬만 깨짐\"은 아래 순서로 좁히면 대부분 분리된다.<br>\n      1. runtime version — 나와 팀/CI의 런타임 버전이 같은가<br>\n      2. env diff — 환경변수·credential 누락 또는 값 차이<br>\n      3. port/process — 충돌 포트·좀비 프로세스가 잡고 있는가<br>\n      4. clean install — lockfile 기준 재설치로 의존성 오염 제거<br>\n      5. container — 그래도 재현 안 되면 컨테이너 기준으로 통제\n    </div>\n    <table>\n      <tr><th>순서</th><th>질문</th><th>증거</th></tr>\n      <tr><td>1</td><td>런타임 버전이 팀/CI와 같은가?</td><td><code>node -v</code>, <code>java -version</code>, lockfile</td></tr>\n      <tr><td>2</td><td>env·credential 누락/차이인가?</td><td><code>.env</code> template diff, secret 이름·만료</td></tr>\n      <tr><td>3</td><td>포트·프로세스 충돌인가?</td><td><code>lsof -i :3000</code>, <code>ps aux | grep node</code></td></tr>\n      <tr><td>4</td><td>의존성·캐시 오염인가?</td><td><code>rm -rf node_modules</code> + <code>npm ci</code>, lockfile diff</td></tr>\n      <tr><td>5</td><td>컨테이너 기준으론 재현되나?</td><td><code>docker compose up</code>, image digest</td></tr>\n    </table>\n    <div class=\"callout risk\"><span class=\"co-label\">복구/중단 기준</span><p>작업 유실이 의심되면 다른 명령을 치기 전에 <b><code>git reflog</code>부터</b> — HEAD 이동 기록이 남아 있는 동안이 복구 골든타임이다. secret이 커밋·push됐다면 history 정리보다 <b>토큰 재발급이 먼저</b>다. 히스토리 재작성(rebase/force)은 공유 브랜치에서 중단하고 merge로 우회한다.</p></div>\n  </section>",
};

export default document;
